/*! RESOURCE: /scripts/sn/common/ui/dotwalk/directive.snDotWalkKeyboardHandler.js */
angular
	.module("sn.dot_walk_component")
	.directive("snDotWalkKeyboardHandler", function ($timeout) {
		return {
			restrict: "A",
			link: function (scope, element) {				
				
				$timeout(function(){
					scope.$on("$destroy", function () {
						element.off("keydown");
					});
					scope.closeEvent = 'sn-close-dotwalk-component';
					element.on("keydown", function (e) {
						var _keyCode = e.which || e.keyCode;
						var _$focusedElement = angular.element(e.target);
	
						if (_$focusedElement.length) {
							switch (_keyCode) {
								case 13:
								case 32:
									_enterKeydownHandler(_$focusedElement);
									break;
								case 37:
									_leftKeydownHandler(_$focusedElement);
									break;
								case 38:
									e.preventDefault();
									_upKeydownHandler(_$focusedElement);
									break;
								case 39:
									_rightKeydownHandler(_$focusedElement);
									break;
								case 40:
									e.preventDefault();
									_downKeydownHandler(_$focusedElement);
									break;
								case 27:
									e.preventDefault();
									_escapeKeydownHandler();
									break;
								case 9:
									e.preventDefault();
									_tabKeydownHandler();
									break;
								default:
							}
						} else {
							if (_keyCode === 40) {
								e.preventDefault();
								element
									.find("ul")
									.last()
									.children("li")
									.first()
									.children("a")
									.focus();
							}
						}
					});
				}, 500);
					
				function _enterKeydownHandler(_$focusedElement) {
					_$focusedElement.trigger("click");
				}
				function _rightKeydownHandler(_$focusedElement) {
					var _$ulIndex = _$focusedElement.closest("ul").index();
					var _loadedTable = angular.element(".sn-dot-walk-search-container .breadcrumb_link").eq(_$ulIndex).text().indexOf(_$focusedElement.text().trim()) !== -1;
					
if (_$focusedElement.parents(".dot-walk-item").find(".add-dot-walk-list").length && (!_loadedTable || _$focusedElement.parents('.selected').length)) {
						_$focusedElement.parents(".dot-walk-item").find(".add-dot-walk-list").trigger("click");	
						
scope.$on('referenced_table_loaded', function() {
							_focusNextList(_$focusedElement);
						});
					}
					
					_focusNextList(_$focusedElement);				
				}
				
function _focusNextList(_$focusedElement) {
					$timeout(function(){
						var _$nextDotWalkList = _$focusedElement.closest("ul").next();
						
						if (_$nextDotWalkList.length) {
							if (_$nextDotWalkList.find("li .dot-walk-item.selected").length)
								_$nextDotWalkList.find("li .dot-walk-item.selected .dot-walk-item-label a").focus();
							else if (_$nextDotWalkList.find("li.selected").length)
								_$nextDotWalkList.find("li.selected .dot-walk-item-label a").focus();
							else
								_$nextDotWalkList.children("li").eq(0).find(".dot-walk-item-label a").focus();
						}
					}, 500);
				}
				function _leftKeydownHandler(_$focusedElement) {
					var _$previousDotWalkList = _$focusedElement
						.closest("ul")
						.prev();
					if (!_$previousDotWalkList.length)
						return;
					if (_$previousDotWalkList.find(".selected").length) {
						_$previousDotWalkList
							.find(".selected .dot-walk-item-label a")
							.focus();
					} else {
						_$previousDotWalkList
							.children("li")
							.eq(0)
							.find(".dot-walk-item-label a")
							.focus();
					}
				}
				function _upKeydownHandler(_$focused) {
					var _$previous = _$focused.parents("li").prev().find(".dot-walk-item-label a");
					if (_$previous.length) {
						_$previous.focus();
					} else {
						angular.element("#sn-dot-walk-search").focus();
					}
				}
				function _downKeydownHandler(_$focused) {
					if (_$focused.is("input")) {
						var $listContainer = angular.element("#" + _$focused.attr("aria-owns"));
						$listContainer.find("li a:visible").first().focus();
						return;
					}
					var _$next = _$focused.parents("li").next().find(".dot-walk-item-label a");
					if (_$next.length)
						_$next.focus();
				}
				function _tabKeydownHandler() {
scope.$emit(scope.closeEvent,  true);
				}
				function _escapeKeydownHandler() {
					scope.$emit(scope.closeEvent);
				}
			}
		};
	});
