/*! RESOURCE: /scripts/sn/common/ui/dotwalk/factory.snDotWalkAPI.js */
angular
	.module("sn.dot_walk_component")
	.factory("snDotWalkAPI", function ($http) {
		"use strict";
		function _getEndpoint(table, method) {
return '/api/now/ui/dot_walk/' + table + '/' + method;
		};
		function _cancelRunTransaction() {
			var params = {};
			params.sysparm_request_params = JSON.stringify({sysparm_report_designer_builder : 'true'});
params.sysparm_timer = new Date().getTime();
			params.sysparm_cancel_transaction = true;
			params.sysparm_chartonform = false;
			params.sysparm_processor = 'ChartDataProcessor';
			params.sysparm_scope = 'global';
			params.sysparm_want_session_messages = true;		
			
			var config = { method: 'POST',
							   url: 'xmlhttp.do',
							   data: $j.param(params),
headers: {'Content-Type': 'application/x-www-form-urlencoded'}
							  };
	
			return $http(config);
		}
		return {
			retrievePath: function (table, path, ignoreTables) {
				return _cancelRunTransaction().then(function (response) {
						return $http
							.get(_getEndpoint(table, 'path'), {
								cache: true,
								params: {
									sysparm_ignore: ignoreTables ? ignoreTables.join(',') : '',
									sysparm_path: path
								}
							})
							.then(function (response) {
								return response.data.result;
							})
					});
					
			},
			retrieveTableMetaData: function (table, variableType, id, baseTable) {
				return _cancelRunTransaction().then(function (response) {
						return $http
							.get(_getEndpoint(table, 'table'), {
								cache: true,
								params: {
									sysparm_variable_type: variableType,
									sysparm_cat_item_id: id,
									sysparm_base_table: baseTable
								}
							})
							.then(function (response) {
								return response.data.result;
							})
					});
				
			}
		};
	});
;
