angular.module('sn.ngform.elements').directive('snAutonumberElement', function (getTemplateUrl) {
	"use strict";
	return {
		restrict: 'E',
		replace: true,
		templateUrl: getTemplateUrl('sn_autonumber_element.xml'),
		controller: function($scope) {
			$scope.generateNumber = function(e) {
				$scope.numInput = e.currentTarget.previousSibling;
				$scope.numButton = e.currentTarget;
				var aj = new GlideAjax("GetNextNumberAjax");
				aj.addParam("sysparm_name", e.currentTarget.getAttribute("data-ref"));
				aj.getXML($scope.gotNumber.bind(e), "", new Array(e.currentTarget.getAttribute("data-ref")));
			};
			$scope.gotNumber = function(request){
				var rxml = request.responseXML;
				var numberField = $scope.numInput;
				var items = rxml.getElementsByTagName("item");
				if (items.length > 0) {
					var v = items[0].getAttribute("value");
					numberField.value = v;
					$scope.field.value = v;
					var displayField = $scope.numButton;
					if (displayField)
						displayField.style.display = "none";
				}
			};
		}
	};
});
