angular.module("sn.ngform.elements").directive("snBooleanElement", function (i18n, getTemplateUrl) {
	"use strict";
	return {
		restrict: "E",
		replace: true,
		templateUrl: getTemplateUrl("sn_boolean_element.xml"),
		controller: function($scope){
			var messages;
			i18n.getMessages(["True", "False"], function(response){
				messages = response;
			})
			$scope.booleanChoices = [
				{
					label: messages["True"],
					value: "true"
				},
				{
					label: messages["False"],
					value: "false"
				}
			];
		}
	};
}).directive("snBooleanElementFormatter", function() {
	"use strict";
	return {
		require: "ngModel",
		restrict: "A",
		link: function(scope, element, attrs, ngModel) {
			ngModel.$formatters.push(function(value) {
				if (value === "1") {
					return "true";
				} else if (value === "0") {
					return "false";
				}
				return value;
			});
		}
	}
});
