/*! RESOURCE: /scripts/app.ngFormElements/elements/factory.snCurrency.js */
angular.module('sn.ngform.elements').factory('snCurrencyFactory', function () {
	'use strict';
	function fromRestApi(rawData) {
		var data = rawData;
		return {
			get sysID() {
				return data.sys_id;
			},
			get symbol() {
				return data.symbol;
			},
			get code() {
				return data.code;
			},
			get name() {
				return data.name;
			},
			get isDefault() {
				return data.default;
			},
			get display() {
				return this.symbol + ' (' + this.code + ')';
			},
			update: function(rawData) {
				data = rawData;
			},
			calcScriptValue: function(table, field, value) {
				if (!table || !field || !value)
					return '';
				return "javascript:global.getCurrencyFilter('"
					+ table + "','"
					+ field + "','"
					+ this.code + ";"
					+ value + "')";
			}
		}
	}
	return {
		fromRestApi: fromRestApi
	}
});
;
/*! RESOURCE: /scripts/app.ngFormElements/elements/service.snCurrency.js */
angular.module('sn.ngform.elements').service('snCurrencyService', function($http, $rootScope, snRecordWatcher, snCurrencyFactory) {
	'use strict';
var REST_API_ACTIVE = '/api/now/ui/currency/active';
	var currencies = [];
	var requestPromise = request();
	snRecordWatcher.initChannel('fx_currency', 'active=true');
	$rootScope.$on('record.updated', function(event, response) {
		var record = response.record;
		var found = findSysID(response.sys_id);
		if (record.active && (record.active.value === 'false') && (found.index !== -1)) {
			$rootScope.$apply(function() {
				removeCurrency(found.index);
			});
			return;
		}
		requestPromise = request();
	});
	function request() {
		return $http.get(REST_API_ACTIVE).then(updateCurrencies);
	}
	function updateCurrencies(response) {
		var rawList = response.data.result;
		if (!rawList)
			return;
		currencies.forEach(function(item) {
			item.remove = true;
		});
		rawList.forEach(function(rawData, index) {
			delete insert(rawData, index).remove;
		});
		for (var i = currencies.length - 1; i >= 0; --i)
			if (currencies[i].remove)
				removeCurrency(i);
	}
	function insert(rawData, index) {
		var found = findSysID(rawData.sys_id);
		if (found.item) {
			currencies[found.index].update(rawData);
		} else {
			found.item = snCurrencyFactory.fromRestApi(rawData);
			insertCurrency(index, found.item);
		}
		return found.item;
	}
	function insertCurrency(index, currency) {
		currencies.splice(index, 0, currency);
	}
	function removeCurrency(index) {
		currencies.splice(index, 1);
	}
	function find(field, value) {
		for (var i = 0; i < currencies.length; ++i) {
			if (currencies[i][field] === value) {
				return {
					item: currencies[i],
					index: i
				};
			}
		}
		return {
			index: -1
		};
	}
	function findSysID(sysID) {
		return find('sysID', sysID);
	}
	function findCode(code) {
		return find('code', code).item || currencies[0];
	}
	function parseBetweenValue(betweenCurrencies) {
		var DEFAULT = {
			values: [],
			type: currencies[0]
		};
		if (!betweenCurrencies)
			return DEFAULT;
		var splitCurrencyValues = betweenCurrencies.split("@");
		if (splitCurrencyValues.length !== 2)
			return DEFAULT;
		var map = splitCurrencyValues.map(function(splitValue) {
var values = splitValue.split(/[;,]+/);
			if (values.length < 2)
				return {
					type: currencies[0]
				};
			return {
				type: findCode(values[0]),
				value: values[1]
			}
		});
		return {
			values: [map[0].value, map[1].value],
			type: map[1].type
		};
	}
	function reduceBetweenValue(betweenCurrencies) {
		if (!betweenCurrencies)
			return null;
		if (betweenCurrencies.values.length != 2)
			return null;
		if (betweenCurrencies.values.some(function(currency) {
				return !currency || currency === "null";
			}))
			return null;
		if (!betweenCurrencies.type)
			return null;
		var code = betweenCurrencies.type.code;
		return betweenCurrencies.values.map(function(amount) {
			return code + "," + amount;
		}).join("@");
	}
	return {
		parseBetweenValue: parseBetweenValue,
		reduceBetweenValue: reduceBetweenValue,
		findCode: findCode,
		request: function() {
			return requestPromise;
		},
		get currencies() {
			return currencies;
		},
		get defaultCurrency() {
			return currencies[0];
		},
		extract: function(scriptValue) {
			if (scriptValue) {
var values = /'([^']+);(\d+)'/.exec(scriptValue);
				if (values && values.length >= 3) {
					return {
						type: findCode(values[1]),
						value: values[2]
					};
				}
			}
			return {
				type: this.defaultCurrency,
				value: ''
			};
		}
	}
});
;
/*! RESOURCE: /scripts/app.ngFormElements/elements/directive.snCurrencyElement.js */
angular.module('sn.ngform.elements').directive('snCurrencyElement', function (getTemplateUrl) {
	'use strict';
	return {
		restrict: 'E',
		replace: true,
		templateUrl: getTemplateUrl('sn_currency_element.xml'),
		controller: function($scope, snCurrencyService) {
			$scope.currencies = snCurrencyService.currencies;
			$scope.currency = {};
			var scriptValue = $scope.field.value;
			$scope.field.value = '';
			snCurrencyService.request().then(function() {
				$scope.currency = snCurrencyService.extract(scriptValue);
				$scope.field.value = scriptValue;
			});
			$scope.$watch('field.operator', function(newValue, oldValue) {
				if (newValue === oldValue)
					return;
				$scope.currency.value = '';
			});
			$scope.valueHandler = function valueHandler() {
				var type = $scope.currency.type;
				$scope.field.value = type
						? type.calcScriptValue($scope.field.table, $scope.field.field, $scope.currency.value)
						: '';
				if (typeof $scope.field.onChange === 'function')
					$scope.field.onChange();
			}
		}
	};
});
