/*! RESOURCE: /scripts/app.ngFormElements/elements/directive.snDateElement.js */
angular.module('sn.ngform.elements').directive('snDateElement', function($window, getTemplateUrl, snFormDateHelper) {
	return {
		restrict: 'E',
		replace: true,
		templateUrl: getTemplateUrl("sn_date_time_element.xml"),
		controller: function($scope){
			var config = {
				startView: "day",
				minView : "day",
				dropdownSelector : "glide_date_time_" + $scope.field.ref + "_dropdown"
			};
			$scope.config = angular.extend(config, $scope.field.timepickerConfig);
			$scope.setDateTime = setDateTime;
			$scope.dateTimeOnChangeHandler = dateTimeOnChangeHandler;
			activate();
			function activate(){
				if (typeof $scope.field === "undefined" || typeof $scope.field === "null")
					throw "Invalid field model";
				if (typeof moment === "undefined" || typeof moment === "null")
					throw "Moment.js is unavailable";
				_setMomentLocale();
				_initFieldData();
			}
			function setDateTime(newDateTime, oldDateTime) {
				if (newDateTime === oldDateTime)
					return;
				_toggleDropdownMenu();
				$scope.field.value = snFormDateHelper.addTimezoneOffset(newDateTime);
				$scope.field.displayValue = moment($scope.field.value).format($scope.field.dateFormat);
				_triggerFieldOnChange();
			}
			function dateTimeOnChangeHandler(){
				$scope.dateAsPicker = moment($scope.field.value).format($scope.field.dateFormat);
				_triggerFieldOnChange();
			}
			function _toggleDropdownMenu(){
				angular.element("#" + $scope.config.dropdownSelector).dropdown("toggle");
			}
			function _initFieldData() {
				if ($scope.field.value){
					$scope.field.displayValue = moment($scope.field.value).format($scope.field.dateFormat);
					$scope.dateAsPicker = moment().format(snFormDateHelper.removeTimezoneOffset($scope.field.value), $scope.field.dateFormat);
				} else {
					$scope.field.displayValue = moment().format($scope.field.dateFormat);
					$scope.field.value = snFormDateHelper.addTimezoneOffset($scope.field.displayValue);
					$scope.dateAsPicker = moment().format($scope.field.dateFormat);
				}
			}
			function _setMomentLocale(){
				moment.locale('en', {
					week: {
dow: $window.g_date_picker_first_day_of_week
					}
				});
			}
			function _triggerFieldOnChange(){
				if ($scope.field.onChange && typeof $scope.field.onChange === "function")
					$scope.field.onChange();
			}
		}
	};
});
;
/*! RESOURCE: /scripts/app.ngFormElements/elements/directive.snDateChoiceElement.js */
angular.module('sn.ngform.elements').directive('snDateChoiceElement', function (getTemplateUrl, i18n, filterDateService, snFilterGlobals) {
	"use strict";
	return {
		restrict: 'E',
		replace: true,
		templateUrl: getTemplateUrl('sn_date_choice_element.xml'),
		controller: function($scope){
			var dateValue;
			var NONE_LABEL = i18n.getMessage('-- None --');
			var ERROR_MESSAGE = "failed to look up date value in directive.snDateChoiceElement.js";
			var choiceModel;
			$scope.data = {};
			$scope.timeEdit = false;
			$scope.closeEvent = "close_date_choice";
			$scope.popoverConfig = angular.extend({}, $scope.popoverConfig, {
				placement: 'bottom',
template: '<div class="popover date-choice-popover" role="tooltip"><div class="popover-content"></div></div>'
			});
			$scope.timepickerConfig = {
				startView:'day',
				minView:'day'
			};
			snFilterGlobals.snFilterInitialize($scope.$parent.field.table).then(initialize);
			function initialize() {
				choiceModel = snFilterGlobals.getCalendarValues('dateChoiceModel', $scope.$parent.field.table);
				var model = $scope.field.between ? 'dateChoiceBetweenDisplayValues': 'dateChoiceDisplayValues';
				$scope.data.displayChoices = snFilterGlobals.getCalendarValues(model, $scope.$parent.field.table);
				$scope.$watch('field.field', _fieldOrOperatorChangeHandler);
				$scope.$watch('field.operator', _fieldOrOperatorChangeHandler);
				$scope.dateValueLookup = dateValueLookup;
				$scope.onCalendarDateSet = onCalendarDateSet;
				$scope.buildDateValue = buildDateValue;
				$scope.onInputTimeSet = onInputTimeSet;
				$scope.toggleSection = toggleSection;
				$scope.onKeyPress = onKeyPress;
				_setTimeModels();
				$scope.includeTime = _includeTime();
				if ($scope.field.value){
					_initData()
				} else {
					$scope.data.dateModel = "";
					$scope.data.displayValue = NONE_LABEL;
				}
			}
			function _initData(){
				if ($scope.field.value.indexOf('dateGenerate') > -1){
					_initDateValue();
				} else if (dateLabelLookup($scope.field.value)){
					_initChoiceValue();
				} else {
					var momentDate = moment($scope.field.value);
					$scope.data.displayValue = $scope.field.value;
					$scope.data.dateAsPicker = momentDate.format();
					var timeParts = momentDate.format("HH:mm:ss").split(":");
					_setTimeModels(timeParts);
				}
				$scope.timeEdit = true;
			}
			function toggleSection(choice){
				angular.forEach($scope.data.displayChoices, function(item){
					if (item.type !== choice.type)
						item.show = false;
				});
				choice.show = !choice.show;
			}
			function onKeyPress(event,choice) {
				if (!event) return;
				var currentElement = event.target;
				var keyCode = event.keyCode;
				var key = event.key;
				var currIndex = -1;
				var elements = document.querySelectorAll('.filter-accordion-title, .filter-accordion-section-content[aria-hidden="false"] > ul > li > a');
				for (var i=0; i < elements.length; i++) {
					if (elements[i] === currentElement) {
						currIndex = i;
						break;
					}
				}
				currentElement.tabIndex = -1;
				if (currIndex < 0)
					return;
				if ((key === 'ArrowDown' || keyCode === 40) && elements[++currIndex]) {
						elements[currIndex].focus();
				}
				else if ((key === 'ArrowUp' || keyCode === 38) && elements[--currIndex]) {
						elements[currIndex].focus();
				}
				else if (key === 'Tab' || keyCode === 9) {
					currentElement.tabIndex = 0;
				}
				else if (isSectionHeader(elements[currIndex])) {
					if (isToggleOpen(choice.show)) {
						if (key === 'ArrowLeft' || keyCode === 37)
							toggleSection(choice);
					}
					else {
						if (key === 'ArrowRight' || keyCode === 39)
							toggleSection(choice);
					}
				}
			}
			function isSectionHeader(element) {
				return (element.className.indexOf('filter-accordion-title') !== -1) ? true: false;
			}
			function isToggleOpen(toggled) {
				return Boolean(toggled);
			}
			function _initDateValue(){
var dateParts = $scope.field.value.split(/'|@/).filter(function(item){
					return (item !== 'javascript:gs.dateGenerate(' && item !== ',' && item !== ')');
				});
				var timeParts;
				$scope.data.dateAsPicker = moment(dateParts[0]).format();
				if (_includeTime()){
					$scope.data.displayValue = _getDisplayValue(dateParts[0], dateParts[1]);
timeParts = dateParts[1].split(/:|\./);
					_setTimeModels(timeParts);
				} else {
					$scope.data.displayValue = _getDisplayValue(dateParts[0], dateParts[1]);
				}
			}
			function _initChoiceValue(){
				dateValue = dateLabelLookup($scope.field.value);
				var dateChoice = choiceModel
					.filter(function(item){
						return (item.value == dateValue);
					})[0];
				$scope.data.displayValue = dateChoice.label;
			}
			function buildDateValue(dateChoice){
				_reset();
				$scope.$broadcast($scope.closeEvent);
				dateValue = dateChoice.value;
				$scope.data.displayValue = dateChoice.label;
				buildFieldValue()
			}
			function onInputTimeSet(data){
				if (data.hours === null)
					data.hours = 0;
				if (data.minutes === null)
					data.minutes = 0;
				if (data.seconds === null)
					data.seconds = 0;
				data.hours = Math.round(data.hours);
				data.minutes = Math.round(data.minutes);
				data.seconds = Math.round(data.seconds);
				_sanitizeTimeValues(data);
				var date = moment($scope.data.displayValue, _getSystemDateFormat()).format("YYYY-MM-DD");
				var time = _pad(data.hours, 2) + ":" + _pad(data.minutes, 2) + ":" + _pad(data.seconds, 2);
				var momentDate = moment(date + " " + time);
				$scope.data.displayValue = _getDisplayValue(date, time);
				buildFieldDateValue(momentDate.format("YYYY-MM-DD"), momentDate.format("HH:mm:ss"));
			}
			function onCalendarDateSet(newDate) {
				var momentDate = moment().set({
					'year': newDate.getFullYear(),
					'month': newDate.getMonth(),
					'date': newDate.getDate(),
					'hour': $scope.data.hours,
					'minute': $scope.data.minutes,
					'second': $scope.data.seconds,
				});
				var date = momentDate.format("YYYY-MM-DD");
				var time = momentDate.format("HH:mm:ss");
				$scope.data.dateAsPicker = new Date(momentDate).toUTCString();
				$scope.data.displayValue = _getDisplayValue(date, time);
				$scope.timeEdit = true;
				buildFieldDateValue(date, time);
				if (!$scope.includeTime)
					$scope.$broadcast($scope.closeEvent);
			}
			function buildFieldValue(){
				try{
					$scope.field.value = dateValueLookup(dateValue);
					if ($scope.field.onChange && typeof $scope.field.onChange === "function")
						$scope.field.onChange();
				} catch(ex){
					console.warn(ERROR_MESSAGE, ex);
				}
			}
			function buildFieldDateValue(date, time){
				try {
				$scope.field.displayValue = _getDisplayValue(date, time);
				if (!isEncrypted()){
					if (_includeTime()){
						$scope.field.value = "javascript:gs.dateGenerate('" + date +"','" + time +"')";
					} else {
						var values = [
							date,
							"javascript:gs.dateGenerate('" + date +"','start')",
							"javascript:gs.dateGenerate('" + date +"','end')"
						];
						$scope.field.value = values.join("@");
					}
				} else {
					$scope.field.value = $scope.field.displayValue;
				}
				if ($scope.field.onChange && typeof $scope.field.onChange === "function")
					$scope.field.onChange();
				} catch(ex) {
					console.warn(ERROR_MESSAGE, ex);
				}
			}
			function dateValueLookup (value){
				return filterDateService.dateValueLookup($scope.field.operator, value, $scope.$parent.field.table);
			}
			function dateLabelLookup (value){
				return filterDateService.dateLabelLookup($scope.field, value, $scope.$parent.field.table);
			}
			function _fieldOrOperatorChangeHandler(n, o){
				if (n === o)
					return;
				$scope.includeTime = _includeTime();
				_reset();
			}
			function _includeTime(operator){
				operator = typeof operator === "undefined" ?  $scope.field.operator : operator;
				return !(operator == "ON" || operator == "NOTON");
			}
			function _pad(num, size) {
				var s = num + "";
				while (s.length < size) s = "0" + s;
				return s;
			}
			function _reset(){
				$scope.data.dateModel = "";
				$scope.data.dateAsPicker = "";
				$scope.data.displayValue = NONE_LABEL;
				$scope.timeEdit = false;
				_setTimeModels();
			}
			function _getDisplayValue(dateParam, timeParam){
				if (_includeTime()){
					var date = moment(dateParam + " " + timeParam).format(_getSystemDateFormat());
					var time = moment(dateParam + " " + timeParam).format(_getSystemTimeFormat());
					var selectedField = $scope.field.field;
					if ($scope.field.baseFields[selectedField] && $scope.field.baseFields[selectedField].internal_type === "glide_date" && isEncrypted())
						return date;
					return date + " " + time;
				} else {
					var date = moment(dateParam).format(_getSystemDateFormat());
					return date;
				}
			}
			function _getSystemDateFormat(){
				var dateFormat = "yyyy-MM-dd";
				if (window.NOW && window.NOW.dateFormat && window.NOW.dateFormat.dateStringFormat) {
                    dateFormat = window.NOW.dateFormat.dateStringFormat;
                } else if (typeof g_user_date_format !== 'undefined' && g_user_date_format) {
                    dateFormat = g_user_date_format;
				}
				return dateFormat.toUpperCase();
			}
			function _getSystemTimeFormat(){
				var timeFormat = "HH:mm:ss";
				if (window.NOW && window.NOW.dateFormat && window.NOW.dateFormat.timeStringFormat)
					timeFormat = window.NOW.dateFormat.timeStringFormat;
				return timeFormat;
			}
			function _setTimeModels(array){
				if (typeof array === "undefined" || array.length !== 3)
					array = [0,0,0];
				$scope.data.hours = parseInt(array[0], 10);
				$scope.data.minutes = parseInt(array[1], 10);
				$scope.data.seconds = parseInt(array[2], 10);
			}
			function _sanitizeTimeValues(data){
				if (typeof data.hours === "undefined" || data.hours > 23)
					data.hours = 23;
				if (typeof data.minutes === "undefined" || data.minutes > 59)
					data.minutes = 59;
				if (typeof data.seconds === "undefined" || data.seconds > 59)
					data.seconds = 59;
			}
			function isEncrypted() {
				var isEdgeEncrypted = $scope.field.baseFields[$scope.field.field] && $scope.field.baseFields[$scope.field.field].edge_encrypted;
				var isEncrypted = $scope.field.baseFields[$scope.field.field] && $scope.field.baseFields[$scope.field.field].glide_encrypted;
				return ((isEdgeEncrypted !== "undefined" && isEdgeEncrypted == true)
					|| (isEncrypted !== "undefined" && isEncrypted == true))
			}
		}
	};
});
