						$scope.fields = snDotWalkUtilities.makeDateFieldsArray($scope.field.baseFields, $scope.$parent);
					if ($scope.fields.length !== 0)
						$scope.fieldModel = $scope.fields[0].field;
					$scope.displayValue = NONE_LABEL;
