/*! RESOURCE: /scripts/app.ngFormElements/elements/directive.snDateTimeElement.js */
angular.module('sn.ngform.elements').directive('snDateTimeElement', function($window, getTemplateUrl, snFormDateHelper) {
	return {
		restrict: 'E',
		replace: true,
		templateUrl: getTemplateUrl("sn_date_time_element.xml"),
		controller: function($scope){
			var config = {
				startView: "day",
				minView : "minute",
				dropdownSelector : "glide_date_time_" + $scope.field.ref + "_dropdown",
				renderOn: 'datepicker.render'
			};
			$scope.config = angular.extend(config, $scope.field.timepickerConfig);
			$scope.setDateTime = setDateTime;
			$scope.dateTimeOnChangeHandler = dateTimeOnChangeHandler;
			activate();
			function activate(){
				if (typeof $scope.field === "undefined" || typeof $scope.field === "null")
					throw "Invalid field model";
				if (typeof moment === "undefined" || typeof moment === "null")
					throw "Moment.js is unavailable";
				_initFieldData();
				_setMomentLocale();
			}
			function setDateTime(newDate, oldDate) {
				if (newDate === oldDate)
					return;
				_toggleDropdownMenu();
				$scope.field.value = moment(newDate).format("YYYY-MM-DD HH:mm:ss");
				$scope.field.displayValue = moment(newDate).format($scope.field.dateFormat);
				_triggerFieldOnChange();
			}
			function dateTimeOnChangeHandler() {
				if (!moment($scope.field.displayValue, $scope.field.dateFormat).isValid())
					return;
				$scope.field.value = $scope.field.displayValue;
				$scope.dateAsPicker = moment($scope.field.value).format($scope.field.dateFormat);
				_triggerFieldOnChange();
			}
			function _toggleDropdownMenu() {
				angular.element("#" + $scope.config.dropdownSelector).dropdown("toggle");
			}
			function _initFieldData() {
				if ($scope.field.value){
					if (!$scope.field.displayValue)
						$scope.field.displayValue = moment($scope.field.value).format($scope.field.dateFormat);
					$scope.dateAsPicker = moment($scope.field.value).format("YYYY-MM-DD HH:mm:ss");
				} else {
					$scope.field.displayValue = moment().format($scope.field.dateFormat);
					$scope.field.value = snFormDateHelper.addTimezoneOffset("YYYY-MM-DD HH:mm:ss");
					$scope.dateAsPicker = moment().format($scope.field.dateFormat);
				}
			}
			function _setMomentLocale(){
				var firstDayOfWeek = parseInt($window.g_date_picker_first_day_of_week,10) || 1;
				moment.locale('en', {
					week: {
						dow: Math.min(Math.max(firstDayOfWeek - 1, 0), 6)
					}
				});
			}
			function _triggerFieldOnChange(){
				if ($scope.field.onChange && typeof $scope.field.onChange === "function")
					$scope.field.onChange();
			}
		},
		link: function(scope, element) {
			const keyHandler = (event) => {
if (event.key === "Enter" || event.keyCode === 13)
					return;
				const targetElement = event.target;
				const dropDown = angular.element(targetElement).closest('.dropdown-menu');
				const focusableElements = dropDown.find('th, td, span').filter(':visible').filter('[tabindex="0"]');
				if (focusableElements.length === 0) {
					return;
				}
				const currentIndex = focusableElements.index(document.activeElement);
				let nextIndex = -1;
				if (event.key === 'Tab' || event.keyCode === 9) {
if (event.shiftKey) {
						nextIndex = currentIndex - 1;
} else {
						nextIndex = currentIndex + 1;
					}
				}
				else if (event.key === 'ArrowUp' || event.key === 'ArrowDown' || event.key === 'ArrowLeft' || event.key === 'ArrowRight') {
					const nodesPerRow= targetElement.closest('table').className.includes('day-view') ? 7 : 4;
					if (event.key === 'ArrowUp') {
						nextIndex = currentIndex - nodesPerRow;
					} else if (event.key === 'ArrowDown') {
						nextIndex = currentIndex + nodesPerRow;
					} else if (event.key === 'ArrowLeft') {
						nextIndex = currentIndex - 1;
					} else if (event.key === 'ArrowRight') {
						nextIndex = currentIndex + 1;
					}
				}
nextIndex = (nextIndex + focusableElements.length) % focusableElements.length;
				focusableElements[nextIndex].focus();
				event.stopPropagation();
				event.preventDefault();
			};
			element.on('show.bs.dropdown', function() {
				scope.$broadcast('datepicker.render');
				setTimeout(() => {
					focusOnActiveDate(element)
					document.addEventListener('keydown', keyHandler, true)
				}, 0);
			});
			element.on('hidden.bs.dropdown', function() {
				angular.element('input', angular.element('[id="' + scope.config.dropdownSelector + '"]')).focus();
				document.removeEventListener('keydown', keyHandler, true);
			});
			function focusOnActiveDate(element) {
const activeDateElement = element.find('.day.active');
				if (activeDateElement.length) {
					activeDateElement.focus(); 
					activeDateElement.on('focus', function(event) {
						event.stopPropagation();
						event.preventDefault();
					});
				}
			}
		}
	};
});
;
