angular.module('sn.ngform.elements').directive('snReferenceElement', function (getTemplateUrl, $http) {
	"use strict";
	var requestCount = 0;
	return {
		restrict: 'E',
		replace: true,
		templateUrl: getTemplateUrl('sn_reference_element.xml'),
		controller: function($scope, $element, $attrs){
			$scope.field = $scope.field || $scope.$eval($attrs.field);
			$scope.$watch('field.suggestion', function(n,o){
				if (n !== o){
					addSuggestionToQuery();
				}
			});
			if (!Bloodhound){
				return;
			}
			var displayFieldKey = $scope.field.reference_display_field || $scope.field.display_field;
			var bHound = new Bloodhound({
				datumTokenizer: function(d) { return Bloodhound.tokenizers.whitespace(d.displayValue); },
				queryTokenizer: Bloodhound.tokenizers.whitespace,
				identify: function(obj){ return obj.sysId},
				local: []
			});
			var initialized = false;
			var wildcard = false;
			var idArray;
			var data;
			var query;
			var displayField = (displayFieldKey instanceof Array) ? displayFieldKey : [displayFieldKey];
			$scope.config = {
				minLength: 1,
				highlight: true
			};
			$scope.referenceData = {
				displayKey: 'displayValue',
				source: typeaheadWithWildcard,
				limit: 15
			};
			$scope.$watch('field.suggestion', function(n, o){
				if (n !== o && n === "**"){
					wildcard = true;
					getData();
				} else if ( n !== o &&  n != null){
					wildcard = false;
					getData();
				}
			});
			$scope.$watch('field.targetTable', function(n, o){
				if ( n !== o ){
					bHound.clear();
				}
			});
			function typeaheadWithWildcard(q, sync){
				if (q === "**"){
					sync(bHound.get(idArray));
				} else {
					bHound.search(q, sync);
				}
			}
			$scope.activate = function activate(){
				bHound.initialize();
				getData();
			};
			function getData(){
				if (!$scope.field.suggestion) {
					data = [];
					addData();
					return;
				}
				var field = $scope.field.display_field || 'name';
				query = (wildcard) ? "" : field + "STARTSWITH" + $scope.field.suggestion;
				var params = {
					sysparm_query: query || '',
					sysparm_fields: displayField,
					sysparm_reference_field: $scope.field.name,
					sysparm_referring_table : $scope.field.table,
					sysparm_referring_record_id: $scope.field.sysId,
					sysparm_display_value: 'all',
					sysparm_exclude_reference_link: 'true',
					sysparm_field_styles: 'true',
					sysparm_timer: ++requestCount,
					sysparm_completer_id: $scope.field.table + '.' + $scope.field.name
				};
$http.get("/api/now/ui/table/" + $scope.field.targetTable, {
					params: params
				}).then(function(response){
					data = response.data.result.records[0].records.map(function (obj) {
						try {
							return {
								displayValue: obj.data[displayField].display_value,
								sysId: obj.sys_id
							};
						} catch(e) {
							return {
								displayValue: obj.metadata.display_value,
								sysId: obj.sys_id
							};
						}
					});
					addData();
				})
			}
			function addData() {
				if (wildcard){
					_createArrayOfIds();
				}
				bHound.add(data);
				if (!initialized){
					initialized = true;
					return;
				}
				$scope.$broadcast('openTypeahead');
			}
			function _createArrayOfIds(){
				idArray = [];
				var length = (data.length < $scope.referenceData.limit) ? data.length : $scope.referenceData.limit;
				for(var i = 0; i < length; i++){
					idArray.push(data[i].sysId);
				}
			}
			function addSuggestionToQuery(){
				$scope.query = $scope.field.suggestion ? $scope.field.display_field + "STARTSWITH" + $scope.field.suggestion : '';
			}
		}
	};
});
;
