/*! RESOURCE: /scripts/app.ngFormElements/util/directive.snFilterWidgetBetweenElement.js */
angular.module('sn.ngform.elements').directive('snFilterWidgetBetweenElement', function (getTemplateUrl) {
	"use strict";
	return {
		restrict: 'E',
		replace: true,
		scope:{
			field: '=',
			popoverConfig: '='
		},
		templateUrl: getTemplateUrl('sn_filter_widget_between_element.xml'),
		controller: function($scope) {
			activate();
			function activate() {
				var field = $scope.field;
				var values = (field.value || "@").split("@").map(function(v) {
					return v.trim();
				});
				$scope.field1 = createFieldModel(field, values[0], field.betweenType, 'BETWEEN_A');
				$scope.field2 = createFieldModel(field, values[1], field.betweenType, 'BETWEEN_B');
				$scope.$watch('field1.value + field2.value', function(n, o) {
					if (n != o){
						if ($scope.field1.value && $scope.field2.value)
							field.value = $scope.field1.value + "@" + $scope.field2.value;
						if (field.onChange && typeof field.onChange === "function")
							field.onChange();
					}
				});
			}
			function createFieldModel (obj, value, type, operator) {
				return Object.create(obj, {
					value: {
						writable: true,
						value: value
					},
					advancedEditor: {
						value: type
					},
					operator: {
						value : obj.betweenType === 'glide_date_choice' ? operator : obj.operator
					},
					between : {
						value: true
					},
					onChange: {
						writable: true,
						value: null
					}
				});
			}
		}
	};
});
;
