/*! RESOURCE: /scripts/app.ngFormElements/util/service.snFormDateHelper.js */
(function(){
	angular.module('sn.ngform.elements').factory('snFormDateHelper', function () {
		var d,
			hours;
		
		if (typeof g_tz_offset !== "undefined"){
			d = moment.duration(g_tz_offset, 'milliseconds');
			hours = Math.floor(d.asHours());
		} else{
			d = 0;
			hours = 0;
		} 
		return {
			removeTimezoneOffset: removeTimezoneOffset,
			addTimezoneOffset: addTimezoneOffset
		};
		function removeTimezoneOffset(value){
			if (moment(value).isDST())
				return moment(value).subtract(Math.abs(hours) - 1, 'hours').format("YYYY-MM-DD HH:mm:ss");
			else
				return moment(value).subtract(Math.abs(hours), 'hours').format("YYYY-MM-DD HH:mm:ss");
		}
		function addTimezoneOffset(value){
			if (moment(value).isDST())
				return moment(value).add(Math.abs(hours) - 1, 'hours').format("YYYY-MM-DD HH:mm:ss");
			else
				return moment(value).add(Math.abs(hours), 'hours').format("YYYY-MM-DD HH:mm:ss");
		}
	});
})();
;
