/*! RESOURCE: /scripts/app.ngFormElements/util/directive.snDurationFormatter.js */
angular.module('sn.ngform.elements').directive('snDurationFormatter', function () {
	"use strict";
	return {
		require: "ngModel",
		restrict: "A",
		link: function(scope, element, attrs, ngModelCtrl) {
			var theDawnOfTime;
			ngModelCtrl.$formatters.push(function() {
				if (!scope.field.value)
					return {days: 0, hours: 0, minutes: 0, seconds: 0}
				theDawnOfTime = moment.unix(0).utc();
				var fieldValueMoment = moment.utc(scope.field.value, 'YYYY-MM-DD HH:mm:ss');
				var duration = moment.duration(fieldValueMoment.diff(theDawnOfTime));
				var days = Math.floor(duration.asDays());
				var	hours = duration.get('hours');
				var	minutes = duration.get('minutes');
				var	seconds = duration.get('seconds');
				var maxUnit = scope.field.maxUnit;
				if (maxUnit == 'hours') {
					days = 0;
					hours = Math.floor(duration.asHours());
				}
				if (maxUnit == 'minutes') {
					days = hours = 0;
					minutes = Math.floor(duration.asMinutes());
				}
				if (maxUnit == 'seconds') {
					days = hours = minutes = 0;
					seconds = duration.asSeconds();
				}
				return {
					days: days,
					hours: hours,
					minutes: minutes,
					seconds: seconds
				};
			});
			ngModelCtrl.$render = function() {
				scope.days = ngModelCtrl.$viewValue.days;
				scope.hours = ngModelCtrl.$viewValue.hours;
				scope.minutes = ngModelCtrl.$viewValue.minutes;
				scope.seconds = ngModelCtrl.$viewValue.seconds;
			};
			ngModelCtrl.$parsers.push(function(model) {
				theDawnOfTime = moment.unix(0).utc();
				var modelValue = moment.duration(model);
				var newValue = theDawnOfTime.add(modelValue).format("YYYY-MM-DD HH:mm:ss");
				return newValue;
			});
			scope.$watch('days + hours + minutes + seconds', function() {
				ngModelCtrl.$setViewValue({
					days: scope.days,
					hours: scope.hours,
					minutes: scope.minutes,
					seconds: scope.seconds
				});
			});
		}
	};
});
;
/*! RESOURCE: /scripts/app.ngFormElements/util/directive.snFilterTextareaFormatter.js */
angular.module('sn.ngform.elements').directive('snFilterTextareaFormatter', function () {
	"use strict";
	return {
		require: "ngModel",
		restrict: "A",
		link: function(scope, element, attrs, ngModelCtrl) {
			ngModelCtrl.$parsers.push(_toModel);
			ngModelCtrl.$formatters.push(_toView);
			function _toModel(input){
				if (!input)
					return;
var normalized = input.split(/[,\n]+/g);
				var normalizedString = normalized.filter(_removeEmptyStrings).join(",");
				return normalizedString;
			}
			function _toView(input){
				if (input)
return input.replace(/[,]/g, ",\n");
				return input;
			}
			function _removeEmptyStrings(item){
				return item;
			}
		}
	};
});
;
/*! RESOURCE: /scripts/app.ngFormElements/util/directive.snReferenceFormatter.js */
angular.module('sn.ngform.elements').directive('snReferenceFormatter', function () {
	"use strict";
	return {
		require: "ngModel",
		restrict: "A",
		link: function(scope, element, attrs, ngModelCtrl) {
			var originalValue = scope.field.displayValue;
			ngModelCtrl.$parsers.push(function(model){
				if (model !== '') {
					if (angular.isObject(model)) {
						scope.field.value = model.sysId;
						scope.field.suggestion = null;
						return originalValue = scope.field.displayValue = model.displayValue;
					} else {
						scope.field.suggestion = model;
						return originalValue;
					}
				} else {
					return originalValue = scope.field.displayValue = scope.field.value = model;
				}
			});
		}
	};
});
;
