/*! RESOURCE: scripts/directive.snCurrency2Element.js */
angular.module('sn.ngform.elements').directive('snCurrency2Element', function(getTemplateUrl) {
  'use strict';
  return {
    restrict: 'E',
    replace: true,
    templateUrl: getTemplateUrl('sn_currency_element.xml'),
    controller: function($scope, snCurrencyService) {
      $scope.currencies = snCurrencyService.currencies;
      $scope.currency = {};
      var fieldValue = $scope.field.value;
      $scope.field.value = '';
      snCurrencyService.request().then(function() {
        if (!fieldValue) {
			$scope.currency.type = snCurrencyService.defaultCurrency;
			return;
        }
var values = fieldValue.split(/,(.+)/);
        $scope.currency.type = snCurrencyService.findCode(values[0]);
        $scope.currency.value = values[1];
        $scope.field.value = fieldValue;
      });
      $scope.$watch('field.operator', function(newValue, oldValue) {
        if (newValue === oldValue)
          return;
        $scope.currency.value = '';
      });
      $scope.valueHandler = function valueHandler() {
        var type = $scope.currency.type;
        var currencyValue = (type) ? type.code : "";
        var amountValue = $scope.currency.value;
        $scope.field.value = currencyValue + "," + amountValue;
        if (typeof $scope.field.onChange === 'function')
          $scope.field.onChange();
      }
    }
  };
});
;
;
