angular.module('sn.ngform.components.reference_selector').directive('snReferenceSelector', function(getTemplateUrl, snCustomEvent, snReferenceSelectorService) {
	"use strict";
	return {
		restrict: 'E',
		templateUrl: getTemplateUrl("sn_reference_selector.xml"),
		scope: {
			target:"@",
			referringRecordId:"@",
			referringTable:"@",
			referenceKey:"@",
			dependentField:"@",
			query:"@",
			popoverConfig: "=",
			closeEvent: "@",
			loadEvent: "@",
			ref: "@",
			targetTable: "@",
			buttonTabIndex: "@",
			referenceLabel: "@"
		},
		replace: true,
		controller: function($scope, $element) {
			$scope.clearStack = true;
			$scope.query = '';
			$scope.sysparmView = "sys_ref_list";
			$scope.listType = "reference";
			$scope.encodedQueryRecord = angular.element('#sysparm_encoded_record').val();
			$scope.loaded = false;
			$scope.referenceField = $scope.target.substring($scope.target.indexOf('.') + 1);
			var originalValue;
var modal = $element.find('.modal')[0],
modalParent = null;
			angular.element(modal).on('show.bs.modal', function(evt) {
					var displayField = angular.element("#sys_display." + $scope.ref);
					if (typeof originalValue === undefined) {
						originalValue = angular.element("#sys_display.original." + $scope.ref).value;
					}
					if (displayField.value != originalValue) {
						$scope.referenceFieldValue = displayField.value;
						originalValue = displayField.value;
					}
					var srcModal = evt.target;
					if (srcModal != modal)
						return;
					modalParent = modal.parentNode;
					angular.element(modal).appendTo('body');
					$scope.loaded = true;
					$scope.$evalAsync();
				})
				.on('hidden.bs.modal', function(evt) {
					var srcModal = evt.target;
					if (srcModal != modal)
						return;
					angular.element(modal).appendTo(modalParent);
					angular.element(modal).find('sn-list').scope().$destroy();
					$scope.loaded = false;
					$scope.$evalAsync();
				});
			if (window.g_form) {
				snCustomEvent.observe('show.complexpopover.' + $scope.ref, function() {
					var elem = angular.element('sys_display.' + $scope.ref);
					var originalValElem = angular.element('sys_display.original.' + $scope.ref);
					if (!originalValElem) {
						return;
					}
					if (elem.value === originalValElem.value) {
						$scope.query = '';
						return;
					}
					if (elem.value && elem.attr('ac_order_by')) {
						$scope.query = elem.attr('ac_order_by') + "STARTSWITH" + elem.value;
					}
				});
				snCustomEvent.observe('form.isModified', setChangedValues);
			}
			function setChangedValues() {
				var desiredFields = window.g_form.modifiedFields || {};
				$scope.referringRecordChangedValues = snReferenceSelectorService.getModifiedFieldValues(desiredFields, $scope.referringTable);
				var dependentFieldEl = gel("sys_original." + $scope.referringTable + "." + $scope.dependentField);
				if (window.g_form.hasField($scope.dependentField) && dependentFieldEl && g_form.getValue($scope.dependentField) !== dependentFieldEl.value) {
					desiredFields[$scope.dependentField] = true;
				}
			}
			snCustomEvent.observe('list.record_select', function(data) {
				if (data.ref == $scope.ref) {
					angular.element(data.event.target)
						.closest('.modal')
						.modal('hide');
					data.event.preventDefault();
				}
			});
			$scope.$on("$destroy", function() {
				angular.element(modal).modal('hide');
			});
		}
	};
});
;
/*! RESOURCE: /scripts/app.ngFormElements/components/reference_selector/service.snReferenceSelectorService.js */
angular.module('sn.ngform.components.reference_selector').service('snReferenceSelectorService', function() {
	"use strict";
	return {
		getModifiedFieldValues: getModifiedFieldValues
	};
	function getModifiedFieldValues(fields){
		var modifiedFields = {};
		if (!window.g_form){
			console.warn("g_form is undefined");
			return;
		}
		for (var key in fields) {
			if (fields.hasOwnProperty(key)) {
				if (key.indexOf(".") > -1){
					key = key.split('.').splice(1,2).join('.');
				}
				modifiedFields[key] = window.g_form.getValue(key);
			}
		}
		return modifiedFields;
	}
});
;
