/*! RESOURCE: /scripts/app.ngFormElements/components/record_preview/service.snRecordPreviewService.js */
angular.module('sn.ngform.components.record_preview').service('snRecordPreviewService', function($http, $q, urlTools){
	"use strict";
var TABLE_DATA = "/api/now/ui/table/";
	var layoutCache = {};
	return {
		getFields: getFields,
		getTableData: getTableData
	};
	function getFields(table, sysId, view, field) {
		var layoutCacheKey = [table, sysId, view, field].join('^');
		if (layoutCacheKey in layoutCache){
			return $q.when(layoutCache[layoutCacheKey]);
		}
		var view = view || null;
		var src = urlTools.getURL('popupform', {
			table: table,
			sys_id: sysId,
			view: view,
			field: field
		});
		return $http.post(src)
			.then(function(response){
				layoutCache[layoutCacheKey] = _processFields(response.data[1]);
				return layoutCache[layoutCacheKey];
			})
			.catch(function(){
				console.warn(error);
			});
	}
	function getTableData(table, fields, sysId) {
		var src = TABLE_DATA + table;
		var query = "sys_id=" + sysId;
		return $http({
				cache: false,
				method: "get",
				url: src,
				params: {
					sysparm_query: query,
					sysparm_display_value: true,
					sysparm_fields: fields
				}})
					.then(function(response){
				return response.data.result.records[0].records[0].data;
			}).catch(function(error){
				console.warn(error);
			});
	}
	function _processFields(fields){
		var sections = [];
		var fieldsString = [];
		angular.forEach(fields, function(field){
			var columns = [];
			angular.forEach(field.columns, function(column){
				var fields = [];
				angular.forEach(column.fields, function(field){
					if (_checkComponent(field)){
						fields.push(field);
						fieldsString.push(field.name);
					}
				});
				columns.push(fields);
			});
			sections.push(columns);
		});
		return {
			sections: sections,
			fields: fieldsString.join(",")
		};
	}
	function _checkComponent(field){
		var unsupportedComponent = ["formatter", "annotation", "journal_list", "journal_input", "chart", "embedded"];
		return (unsupportedComponent.indexOf(field.type) === -1);
	}
});
;
/*! RESOURCE: /scripts/app.ngFormElements/components/record_preview/directive.snRecordPreviewForm.js */
angular.module('sn.ngform.components.record_preview').directive('snRecordPreviewForm', function (getTemplateUrl, snRecordPreviewService){
	"use strict";
	return {
		restrict: 'E',
		replace: true,
		templateUrl: getTemplateUrl('sn_record_preview_form.xml'),
		controller: function($scope, snRecordPreviewService){
			var sections;
			var fieldsList;
			activate();
			function activate() {
				var fields = snRecordPreviewService.getFields($scope.targetTable, $scope.sysId, $scope.view, $scope.column);
				fields
					.then(function(fieldsData) {
						sections = fieldsData.sections;
						fieldsList = fieldsData.fields;
						snRecordPreviewService.getTableData($scope.targetTable, fieldsList, $scope.sysId)
							.then(bindColumnsResponse)
							.catch(errorHandler);
				});
			}
			function bindColumnsResponse(response){
				$scope.sections = sections;
				$scope.data = response;
				$scope.$emit($scope.loadEvent);
			}
			function errorHandler(ex){
				console.warn(ex)
			}
			$scope.columnSplitter = function(columns){
				if (columns.length === 1){
					return "col-sm-12";
				} else {
					var classes = [];
classes.push("col-sm-" + parseInt(12/columns.length, 10));
					classes.push("vsplit");
					return classes.join(' ');
				}
			};
			$scope.openNewRecord = function(evt) {
				if ($scope.isForm == "true")
window.location.href = "/" + $scope.targetTable + ".do?sys_id=" + $scope.sysId;
				else {
					$scope.$emit('openRecord', {
						table: $scope.targetTable,
						sysId: $scope.sysId,
						rowIndex: $scope.currentRow,
						event: evt
					});
				}
				$scope.togglePopover();
			};
		}
	};
});
;
