angular.module('sn.filter_widget.data').factory('snFilterInstanceModel', function ($http, $q, i18n, snFilterComparisonFactory, GlideQuery, snFilterInstanceErrors, snFilterUtilities, filterAPI, snCustomEvent, KEYWORD_FIELD) {
	'use strict';
	return {
		create: create
	};
	function create(tableName, relatedEnabled, extendedOperatorOptions, fieldList, includeVariables, tinyURL) {
		var _glideQuery;
		var table = tableName;
		var tableLabel;
		var addRelated = relatedEnabled;
		var filterFieldList = fieldList;
		var tinyUrlQuery = tinyURL;
		var includeVariables = includeVariables;
		snFilterComparisonFactory.setEventHandler(snCustomEvent.fire);
		return {
			initialize: initialize,
			updateTable : updateTable,
			buildQueryString: buildQueryString,
			buildQueryObject: buildQueryObject,
			getSort: getSort,
			setSort: setSort,
			testResult: testResult,
			getTableLabel: getTableLabel
		};
		function initialize(query, table, extendedOperatorOptions) {
			var currentEncodedQuery,
				newEncodedQuery;
			if (_glideQuery)
				currentEncodedQuery = buildQueryString();
			return _getQueryMap(query, table, tinyUrlQuery).then(function(newGlideQuery){
				newEncodedQuery = newGlideQuery.toQueryString();
				if (currentEncodedQuery === newEncodedQuery && !_glideQuery.isEmpty())
					return $q.when(_glideQuery);
				_checkEmptyGlideQuery(newGlideQuery);
				_initializeFilterComparisons(newGlideQuery, extendedOperatorOptions);
				_addRelatedPredicate(newGlideQuery);
				_glideQuery = newGlideQuery;
				return $q.when(_glideQuery);
			});
		}
		function getSort(){
			return _glideQuery.order_by;
		}
		function setSort(sort){
			_glideQuery.order_by = sort;
		}
		function updateTable(tableName){
			table = tableName;
		}
		function isValidTableName(tableName) {
return !/[.%]/.test(tableName);
		}
		function getTableLabel() {
			if (tableLabel)
				return $q.resolve(tableLabel);
			if (!table || !isValidTableName(table))
				return $q.resolve("");
var url = "/api/now/ui/meta/" + table + "/table_label";
			return $http.get(url, {cache: true}).then(function(response) {
				tableLabel = response.data.result;
				return tableLabel;
			});
		}
		function _checkEmptyGlideQuery(glideQuery){
			var subcompound;
			for(var iGQ = 0; iGQ < glideQuery.predicates.length; iGQ++){
				try {
					subcompound = glideQuery.predicates[iGQ].subpredicates[0].subpredicates[0];
					if (!subcompound.subpredicates.length)
						subcompound.addComparison(_getEmptyComparison());
				} catch (ex){
					console.warn(ex);
				}
			}
		}
		function _addRelatedPredicate(glideQuery){
			if (glideQuery.predicates.length === 1 && addRelated){
				var rlCompound = glideQuery.addPredicateCompound(true);
				rlCompound.addRelatedComparison(_getEmptyComparison(true));
				var rlSubcompound = rlCompound.addAnd();
				var rlSubSubcompound = rlSubcompound.addAnd();
				var rlComparison = rlSubSubcompound.addComparison(_getEmptyComparison());
			}
		}
		function _getQueryMap(query, table, tinyUrlQuery){
			var glideQuery;
			if (query instanceof GlideQuery){
				glideQuery = $q.when(new GlideQuery(angular.merge({}, query)));
			} else if (!(query instanceof GlideQuery) && query.predicate) {
				glideQuery = $q.when(new GlideQuery(query));
			} else {
				glideQuery = filterAPI.parseQuery(query, table, tinyUrlQuery).then(function(parts){
					return new GlideQuery(parts);
				});
			}
			return glideQuery;
		}
		function buildQueryString(){
			return new GlideQuery(_glideQuery.toQueryObject()).toQueryString();
		}
		function buildQueryObject(){
			var intermediaryQuery = new GlideQuery(_glideQuery.toQueryObject());
			return snFilterUtilities.filterEmptyComparisonsFromGlideQuery(intermediaryQuery);
		}
		function _initializeFilterComparisons(gq, extendedOperatorOptions) {
			try {
				var predicate;
				var normalizedTable;
				for (var iP = 0; iP < gq.predicates.length; iP++){
					predicate = gq.predicates[iP];
					if (predicate.is_related && predicate.comparison && predicate.comparison.table)
						normalizedTable = predicate.comparison.table.split(".")[0];
					else
						normalizedTable = tableName;
					(predicate.subpredicates || []).forEach(function(compound) {
						(compound.subpredicates || []).forEach(function(subCompound) {
							subCompound.subpredicates = (subCompound.subpredicates || []).map(function(comparison) {
								return snFilterComparisonFactory.create(comparison, normalizedTable, true, extendedOperatorOptions, filterFieldList, includeVariables);
							});
						})
					});
					if (addRelated === false)
						break;
				}
			} catch (ex){
				throw new snFilterInstanceErrors.FilterComparisonInitializationError(ex);
			}
		}
		function testResult(){
			var encodedQuery = buildQueryString();
			return filterAPI.testFilter(encodedQuery, table);
		}
		function _getEmptyComparison(isRelated){
			var comparison;
			var emptyComparison = {
				value : undefined,
				field : "",
				term : "",
				operator : "",
				field_label : i18n.getMessage("-- Choose Field --"),
				term_label : "",
				operator_label : "",
				column_type : "element"
			};
			var relatedComparison = {
				table : undefined,
				options : undefined,
				quantity: {}
			};
			return isRelated ? relatedComparison : emptyComparison;
		}
	}
});
;
