angular.module('sn.filter_widget.data').factory('snFilterInstanceStore', function ($window, snFilterInstanceModel, snFilterUtilities) {
	"use strict";
	var filters = {};
	return {
		create: create,
		get: get,
		remove :remove
	};
	function create(tableName, relatedListQueryConditions, extendedOperatorOptions, fieldList, includeVariables, tinyURL) {
		var uuid = snFilterUtilities.generateKey();
		filters[uuid] = snFilterInstanceModel.create(tableName, relatedListQueryConditions, extendedOperatorOptions, fieldList, includeVariables, tinyURL);
		return uuid;
	}
	function get(tableName){
		if (!filters[tableName])
			return false;
		return filters[tableName];
	}
	function remove(tableName){
		delete filters[tableName];
	}
});
