/*! RESOURCE: /scripts/sn/filter_widget/data/factory.snFilterUtilities.js */
angular.module('sn.filter_widget.data').factory('snFilterUtilities', function (KEYWORD_FIELD) {
	return {
		getComparisons: getComparisons,
		getComparisonKey : getComparisonKey,
		generateKey: generateKey,
		getComparisonIndex: getComparisonIndex,
		filterEmptyComparisonsFromGlideQuery: filterEmptyComparisonsFromGlideQuery,
		getComparisonIndexesObject: getComparisonIndexesObject,
		getRulesets: getRulesets,
		getRulesetIndex: getRulesetIndex,
		getRulesetsBySet : getRulesetsBySet,
		compareTwoObjects: compareTwoObjects,
		convertArrayToObject: convertArrayToObject,
		convertObjectToArray : convertObjectToArray,
		normalizeTable : normalizeTable,
		convertBreadcrumbsToString : convertBreadcrumbsToString,
		canShowKeywordsField : canShowKeywordsField,
		hasExistingKeywordsField : hasExistingKeywordsField
	};
	function getComparisons (gq) {
		var allComparisons = [];
		(gq.predicate.subpredicates || []).map(function(iterativeSet){
			(iterativeSet.subpredicates || []).map(function(ruleSet){
				(ruleSet.subpredicates || []).map(function(comparison){
					allComparisons.push(comparison)
				});
			})
		});
		return allComparisons;
	}
	function filterEmptyComparisonsFromGlideQuery(gq){
		(gq.predicates || []).forEach(function(predicate){
			(predicate.subpredicates || []).forEach(function(compound){
				(compound.subpredicates || []).forEach(function(subCompound){
					subCompound.subpredicates = (subCompound.subpredicates || []).filter(function(comparison){
						return !!comparison.toQueryString();
					});
				})
			});
		});
		return gq;
	}
	function getComparisonIndex(gq, comparison){
		var iterativeSet;
		var iterativeRuleSet;
		var comparisonIndex;
		for (var i = 0; i < gq.predicate.subpredicates.length; i++){
			iterativeSet = gq.predicate.subpredicates[i];
			for (var j = 0; j < iterativeSet.subpredicates.length; j++){
				iterativeRuleSet = iterativeSet.subpredicates[j];
				comparisonIndex = iterativeRuleSet.subpredicates.indexOf(comparison);
				if (comparisonIndex > -1)
					return comparisonIndex;
			}
		}
	}
	function getComparisonIndexesObject(gq, comparison){
		var iterativeSet;
		var iterativeRuleSet;
		var comparisonIndex;
		for (var i = 0; i < gq.predicate.subpredicates.length; i++){
			iterativeSet = gq.predicate.subpredicates[i];
			for (var j = 0; j < iterativeSet.subpredicates.length; j++){
				iterativeRuleSet = iterativeSet.subpredicates[j];
				comparisonIndex = iterativeRuleSet.subpredicates.indexOf(comparison);
				if (comparisonIndex > -1)
					return {compoundIndex : i, subCompoundIndex : j, comparisonIndex : comparisonIndex};
			}
		}
	}
	function getRulesets (gq) {
		var allRuleSets = [];
		(gq.predicate.subpredicates || []).map(function(iterativeSet){
			(iterativeSet.subpredicates || []).map(function(ruleSet){
				allRuleSets.push(ruleSet)
			})
		});
		return allRuleSets;
	}
	function getRulesetsBySet (gq){
		return (gq.predicate.subpredicates || []).map(function(iterativeSet){
			return (iterativeSet.subpredicates || []).map(function(ruleSet){
				return ruleSet;
			})
		});
	}
	function getRulesetIndex(gq, ruleSet){
		var iterativeSet;
		for (var i = 0; i < gq.predicate.subpredicates.length; i++) {
			iterativeSet = gq.predicate.subpredicates[i];
			return iterativeSet.subpredicates.indexOf(ruleSet);
		}
	}
	function generateKey(){
		return Math.random().toString(36).slice(2);
	}
	function getComparisonKey(gq, setIndex, ruleSetIndex, comparisonIndex){
		try {
			return gq.predicate.subpredicates[setIndex].subpredicates[ruleSetIndex].subpredicates[comparisonIndex].comparisonKey;
		} catch (ex){
			console.warn(ex);
		}
	}
	function compareTwoObjects(x, y, properties) {
		if (!properties instanceof Array)
			properties = [properties];
		return properties.every(function(property){
			return x[property] !== y[property]
		});
	}
	function convertArrayToObject(array, key){
		if (!(array instanceof Array) || !key)
			throw "Incorrect Arguments passed to convertArrayToObject";
		var targetObject = {};
		array.forEach(function(item){
			var targetObjectKey = item[key];
			targetObject[targetObjectKey] = item;
		});
		return targetObject;
	}
	function convertObjectToArray(obj, objKey){
		return Object.keys(obj).map(function(key){
			return typeof objKey !== "undefined" ? obj[key][objKey] : obj[key];
		});
	}
	function normalizeTable(table){
		var normalizedTable = table;
		if (table && table.indexOf(".") > -1)
			normalizedTable = table.split(".")[0];
		return normalizedTable;
	}
	function convertBreadcrumbsToString(breadcrumbs){
		if (!breadcrumbs || !(breadcrumbs instanceof Array)	)
			return "";
		breadcrumbs.shift();
		return breadcrumbs
			.map(function(item){
				return item.label
			})
			.join(" > ");
	}
	function hasExistingKeywordsField(predicate) {
		if (!predicate) {
			return false;
		}
		return predicate.subpredicates.some(function(compound) {
			return compound.subpredicates.some(function(subCompound) {
				return subCompound.subpredicates.some(function(comparison) {
					return comparison.field === KEYWORD_FIELD;
				});
			});
		});
	}
	function canShowKeywordsField(predicate, currentComparison) {
		if (!predicate)
			return true;
		if (currentComparison && currentComparison.field === KEYWORD_FIELD)
			return true;
		if (predicate.is_related !== 'undefined' && predicate.is_related)
			return false;
		var existingKeywords = hasExistingKeywordsField(predicate);
		var isOrCondition = predicate.subpredicates.some(function(compound) {
			return compound.subpredicates.some(function(subCompound) {
				return subCompound.subpredicates.indexOf(currentComparison) !== -1 && subCompound.compound_type === 'or';
			});
		});
		var isNewQueryCompound = predicate.compound_type === 'or' && predicate.subpredicates.length > 1;
		return !existingKeywords && !isOrCondition && !isNewQueryCompound;
	}
});
;
