/*! RESOURCE: /scripts/sn/filter_widget/dot_walk/directive.snFilterDotWalkKeydownListener.js */
angular.module('sn.filter_widget.dot_walk').directive('snFilterDotWalkKeydownListener', function() {
	return {
		restrict : "A",
		link : function(scope, element){
			scope.$on("$destroy", function(){
				element.off("keydown");
			});
			element.on("keydown", function(e){
				var _keyCode = e.which || e.keyCode;
				var _$focusedElement = angular.element(e.target);
				if (_$focusedElement.length){
					switch (_keyCode){
						case 13:
							_enterKeydownHandler(_$focusedElement);
							break;
						case 37:
							_leftKeydownHandler(_$focusedElement);
							break;
						case 38:
							e.preventDefault();
							_upKeydownHandler(_$focusedElement);
							break;
						case 39:
							e.preventDefault();
							_rightKeydownHandler(_$focusedElement);
							break;
						case 40:
							e.preventDefault();
							_downKeydownHandler(_$focusedElement);
							break;
						case 27:
							e.preventDefault();
							_escapeKeydownHandler();
							break;
						case 9:
							e.preventDefault();
							_tabKeydownHandler();
							break;
						default :
					}
				} else {
					if (_keyCode === 40){
						e.preventDefault();
						element.find("ul").last().children("li:not(.sr-only)").first().children("a").focus();
					}
				}
			});
			function _enterKeydownHandler(_$focusedElement){
				_$focusedElement.trigger("click");
			}
			function _rightKeydownHandler(_$focusedElement){
				var _$ulIndex = _$focusedElement.closest("ul").index();
				var _loadedTable = angular.element('.filter-breadcrumbs a').eq(_$ulIndex).text().indexOf(_$focusedElement.text()) !== -1;
				var _$nextDotWalkList = _$focusedElement.closest("ul").next();
				if (_$focusedElement.siblings(".add-dot-walk-list").length &&  !_loadedTable)
					_$focusedElement.siblings(".add-dot-walk-list").trigger("click");
				else if (_$nextDotWalkList.length) {
					if (_$nextDotWalkList.children("li.selected").length)
						_$nextDotWalkList.children("li.selected").children("a").focus();
					else
						_$nextDotWalkList.children("li:not(.sr-only)").first().children("a").focus();
				}
			}
			function _leftKeydownHandler(_$focusedElement){
				var _$previousDotWalkList = _$focusedElement.closest("ul").prev();
				if (_$previousDotWalkList.length)
					if (_$previousDotWalkList.children("li.selected").length)
						_$previousDotWalkList.children("li.selected").children("a").focus();
					else
						_$previousDotWalkList.children("li:not(.sr-only)").first().children("a").focus();
			}
			function _upKeydownHandler(_$focused){
				var _$previous = _$focused.parent().prev().children("a");
				if (_$previous.length)
					_$previous.focus();
				else
					angular.element("#filter-fields-search").focus();
			}
			function _downKeydownHandler(_$focused){
				if (_$focused.is('input')) {
					var $listContainer = angular.element('#' + _$focused.attr('aria-owns'));
					$listContainer.find('a').first().focus();
					return;
				}
				var _$next = _$focused.parent().next().children("a");
				if (_$next.length)
					_$next.focus();
			}
			function _tabKeydownHandler() {
scope.$emit(scope.closeEvent,  true);
			}
			function _escapeKeydownHandler() {
				scope.$broadcast(scope.closeEvent);
			}
		}
	}
});
;
/*! RESOURCE: /scripts/sn/filter_widget/dot_walk/directive.snFilterDotWalkPositioner.js */
angular.module('sn.filter_widget.dot_walk').directive('snFilterDotWalkPositioner', function(snCustomEvent) {
	return {
		restrict : 'A',
		link : function(scope){
			snCustomEvent.observe('show.complexpopover.' + scope.ref, showPopover);
			function showPopover($toggleButton) {
				var btn = $toggleButton;
				if (!$toggleButton.hasClass('sn-popover-complex'))
					btn = $toggleButton.closest('.sn-popover-complex');
				if (!btn)
					return;
				var offset = btn.offset();
				offset.top = offset.top + btn.outerHeight() + 5;
				if ($toggleButton.data('bs.popover')) {
					$toggleButton.data('bs.popover').$tip.offset(offset);
				}
			}
			scope.$on('$destroy', function() {
				snCustomEvent.un('show.complexpopover.' + scope.ref, showPopover);
			});
		}
	}
});
;
/*! RESOURCE: /scripts/sn/filter_widget/dot_walk/directive.snFilterFieldList.js */
angular.module('sn.filter_widget.dot_walk').directive('snFilterFieldList', function($q, $timeout, $parse, getTemplateUrl, snDotWalkUtilities, snCustomEvent, snFilterUtilities, KEYWORD_FIELD) {
	"use strict";
	return {
		restrict: 'E',
		replace: true,
		templateUrl: getTemplateUrl("sn_filter_field_list.xml"),
		controller: function($scope, $element, $attrs) {
			var glowTimeout;
			var fieldsModel;
			var _fieldsArray;
			var fieldsListIndex = $parse($attrs.index)($scope);
			$scope.isLoading = true;
			$scope.keyAction = keyAction;
			$scope.selectField = selectField;
			$scope.addReferenceList = addReferenceList;
			$scope.$watch("searchTerm", filterFieldList);
			$scope.$on("snfilter:scrolled_by_index", glowedUpList);
			$scope.$on('$destroy', destroyFilterFieldList);
			$element[0].addEventListener('focus', focusIn ,true);
			$element[0].onfocusin = focusIn;
			activate();
			function activate() {
				$scope.comparison.getFieldsListByIndex(fieldsListIndex)
					.then(_processData);
			}
			function _processData(data) {
				$scope.isLoading = false;
				var filteredFields;
				if ("fields" in data){
					fieldsModel = data.fields;
					var includeKeywords = snFilterUtilities.canShowKeywordsField($scope.predicate, $scope.comparison);
					if (fieldsListIndex !== 0 || $scope.setIndex != 0 || !includeKeywords)
						filteredFields = [KEYWORD_FIELD];
					fieldsModel = _addLabelToDuplicateFields(fieldsModel);
					_fieldsArray = snDotWalkUtilities.makeFieldsArray(fieldsModel, filteredFields);
					$scope.fieldsArray = _fieldsArray;
				}
				$timeout(function() {
					var event = 'set.' + ($scope.setIndex || 0) + '.snFilterFieldList.' + fieldsListIndex + '.' + $scope.ref + '.loaded';
					snCustomEvent.fire(event);
					_addSelectedClass($scope.fieldsArray, data);
					focusFirstItem();
				}, 0);
			}
			function keyAction(keyEvent, field) {
				if (keyEvent.which == 13)
					$scope.selectField(field);
			}
			function selectField(field) {
				var fieldObj = fieldsModel[field.field];
			 	if (fieldObj.base_type === "item_option_new"){
					$scope.$parent.selectVariable(fieldObj, fieldsListIndex);
				} else if (fieldObj && fieldObj.non_selectable) {
					$scope.$parent.selectReferenceList(field, fieldObj, fieldsListIndex);
					_addSelectedClass($scope.fieldsArray, field);
				} else {
					$scope.$parent.selectField(fieldObj, fieldsModel, fieldsListIndex);
					_addSelectedClass($scope.fieldsArray, field);
				}
			}
			function addReferenceList(field) {
				var fieldObj = fieldsModel[field.field];
				$scope.$parent.selectReferenceList(field, fieldObj, fieldsListIndex);
				_addSelectedClass($scope.fieldsArray, field);
			}
			function glowedUpList(event, index){
				if (index == fieldsListIndex) {
					$scope.selected = true;
					if (glowTimeout)
						$timeout.cancel(glowTimeout);
					glowTimeout = $timeout(function(){
						$scope.selected = false;
					}, 500);
				}
			}
			function destroyFilterFieldList(){
				$element[0].removeEventListener('focus', focusIn, true);
				$element[0].onfocusin = null;
			}
			function focusIn(){
				angular.element($element).siblings().removeClass("outline-filter-field-list");
				angular.element($element).addClass("outline-filter-field-list");
			}
			function filterFieldList(n, o){
				$scope.comparison.getFieldsListByIndex(fieldsListIndex).then(function() {
					var title;
					if (n && n != o){
						$scope.fieldsArray = _fieldsArray
							.filter(function(field){
								var isLastColumn = $scope.comparison.fieldsListsPromises.length - 1 === fieldsListIndex;
								var searchMatch = field.field_label ? field.field_label.toLowerCase().indexOf($scope.searchTerm.toLowerCase()) > -1 : false;
								if (field.selected && !isLastColumn){
									title = field;
									return false;
								}
								return searchMatch;
							});
							if (title)
								$scope.fieldsArray.unshift(title);
					} else {
						$scope.fieldsArray = _fieldsArray;
					}
				})
			}
			function _addSelectedClass (array, fieldObj){
				angular.forEach(array, function(item){
					if (fieldObj.field === item.field){
						item.selected = true;
					} else {
						item.selected = false;
					}
				});
			}
			function focusFirstItem(){
				if (fieldsListIndex === $scope.comparison.fieldsListsPromises.length  -1 && fieldsListIndex !== 0) {
					angular.element($element).find('li:not(.sr-only)').first().children('a').focus();
				}
			}
			function _addLabelToDuplicateFields(fieldsModel){
				var labelsArray = Object.keys(fieldsModel).map(function(key){
					return {
						name : fieldsModel[key].name,
						label : fieldsModel[key].label
					}
				});
				var _uniqueNamesFromLabels = _getDuplicateNamesFromLabels(labelsArray);
				_uniqueNamesFromLabels.forEach(function(dupeLabel){
					if (dupeLabel in fieldsModel)
						fieldsModel[dupeLabel].label = fieldsModel[dupeLabel].label + " (" + fieldsModel[dupeLabel].name + ")";
				});
				return fieldsModel
			}
			function _getDuplicateNamesFromLabels(array){
				var hash = {},
					i,
					l = array.length,
					results = [];
				for (i = 0; i < l; i++){
					var item = array[i];
					hash[item.label] = {
						count : item.label in hash ? hash[item.label].count + 1 : 1,
						names : hash[item.label] ? hash[item.label].names.concat([item.name]) : [item.name]
					};
				}
				for (var item in hash) {
					if (hash[item].count > 1){
						results = results.concat(hash[item].names);
					}
				}
				return results;
			}
		}
	};
});
