/*! RESOURCE: /scripts/sn/filter_widget/dot_walk/directive.snFilterFieldListsParent.js */
angular.module('sn.filter_widget.dot_walk').directive('snFilterFieldListsParent', function($q, i18n, $timeout, $http, snCustomEvent, getTemplateUrl) {
	"use strict";
	return {
		restrict: 'E',
		replace: true,
		require: 'ngModel',
		templateUrl: getTemplateUrl("sn_filter_field_lists_parent.xml"),
		scope: {
			ref: "@",
			setIndex: "@",
			comparison: "=",
			dotWalking: "=",
			baseTable: "=",
			uid: "=",
			table: "=",
			closeEvent: "@",
			popoverConfig: "=",
			popoverContainer: "=",
			predicate: '=',
			compoundMessage: '='
		},
		controller: function ($scope) {
			var uid = (!!$scope.uid) ? $scope.uid : $scope.baseTable;
			var container = "#" + uid + "gcond_filters";
			if ($scope.popoverContainer ) {
				container = $scope.popoverContainer;
			}
			else if ($scope.popoverConfig && $scope.popoverConfig.container) {
				container = $scope.popoverConfig.container;
			}
			
			$scope.popoverConfig = {
				placement: 'bottom',
				container : container,
template: '<div class="filter-fields-list-popover popover" role="tooltip"><div class="popover-content"></div></div>',
				onArrowKey: function (evt, callback) {
					if (evt.keyCode == 38 || evt.keyCode == 40) {
						callback(evt);
						evt.preventDefault();
					}
				}
			};
		},
		link: function(scope, iElement, iAttrs, ngModelCtrl) {
			var NONE_LABEL = i18n.getMessage("-- Choose Field --");
			scope.searchTerm;
			scope.displayFields = [];
			scope.selectField = selectField;
			scope.selectReferenceList = selectReferenceList;
			scope.scrollToReferenceList = scrollToReferenceList;
			scope.selectVariable = selectVariable;
			scope.removeFieldList = removeFieldList;
			scope.$on(scope.closeEvent, focusButton);
			ngModelCtrl.$formatters.unshift(toView);
			ngModelCtrl.$render = render;
			snCustomEvent.on('shown.complexpopover.' + scope.ref, toggleFieldSelectedFalse);
			function toggleFieldSelectedFalse() {
				scope.comparison.fieldSelected = false;
			}
			snCustomEvent.on('hide.complexpopover.' + scope.ref, toggleFieldSelectedTrue);
			function toggleFieldSelectedTrue() {
				scope.comparison.fieldSelected = true;
			}
			activate();
			function activate() {
				updateFields();
			}
			function cleanup() {
				snCustomEvent.un('shown.complexpopover.' + scope.ref, toggleFieldSelectedFalse);
				snCustomEvent.un('hide.complexpopover.' + scope.ref, toggleFieldSelectedTrue);
			}
			function render () {
				if (!ngModelCtrl.$viewValue)
					ngModelCtrl.$viewValue = { currentField: NONE_LABEL};
				scope.currentField = ngModelCtrl.$viewValue.currentField;
				$timeout(function() {
					snCustomEvent.fire("snfilter:conditionLabelChange")
				})
			}
			function toView (val) {
				return {
					currentField: val || NONE_LABEL
				};
			}
			function selectReferenceList(field, fieldsModel, index) {
				if (field.reference)
					scope.comparison.addFieldsModel(fieldsModel, index);
				updateFields();
			}
			function selectField(fieldObj, fieldsModel, index) {
				scope.$broadcast(scope.closeEvent);
				scope.comparison.comparisonChange(fieldObj, fieldsModel, index);
				updateFields();
			}
			function selectVariable(field, index) {
				$q.all(scope.comparison.fieldsListsPromises).then(function(values) {
						if (!values[2])
							return;
						scope.$broadcast(scope.closeEvent);
						var fieldsModel = values[2].fields;
						scope.comparison.comparisonChange(field, fieldsModel, index);
				});
			}
			function updateFields () {
				$q.all(scope.comparison.fieldsListsPromises).then(function(values) {
					if (!(values instanceof Array))
						return;
					if (scope.comparison._isVariable())
						scope.display_fields = values[values.length - 1].field_label;
					else {
						scope.display_fields = (values || []).map(function(item, index, values) {
							if (values && values.length > 1 && !item.field_label) {
								return values[index-1].field_label + " Fields"
							} else {
								return item.field_label;
							}
						});
					}
					scrollToReferenceList(values.length);
				});
			}
			function scrollToReferenceList(index) {
				index = index || 0;
				angular.element('.filter-field-sets-container').animate({scrollLeft: index * 250}, 300);
				if (index !== scope.comparison.fieldsListsPromises.length)
					scope.$broadcast('snfilter:scrolled_by_index', index);
			}
			function removeFieldList (index) {
				scope.comparison.fieldsListsPromises.length = index;
				updateFields();
			}
			scope.$on('$destroy', cleanup);
			function focusButton(sourceScope, isTabKey) {
				if (isTabKey)
					scope.comparison.fieldSelected = true;
			}
		}
	};
});
;
/*! RESOURCE: /scripts/sn/filter_widget/dot_walk/factory.snDotWalkUtilities.js */
angular.module('sn.filter_widget.dot_walk').factory('snDotWalkUtilities', function () {
	var DATE_TYPES = ["date", "datetime"];
	var SYS_TAGS = "sys_tags";
	var VARIABLES = "variables";
	return {
		makeFieldsArray: makeFieldsArray,
		makeDateFieldsArray: makeDateFieldsArray,
		removeUnwantedColumnsFromDotwalkedMetadata: removeUnwantedColumnsFromDotwalkedMetadata
	};
	function makeFieldsArray(fields, fieldsToFilter){
		var fieldsArray = _mapFieldsArrayByKeys(fields);
		return fieldsArray.filter(function(fieldObj){
			return ((fieldsToFilter || []).indexOf(fieldObj.field) === -1)
		});
	}
	function makeDateFieldsArray(fields, parent){
		var topLevel;
		try {
			var field = parent.field.field.split('.')
			if (field.length > 1) {
				field.pop();
				topLevel = field.join('.');
			}
		}catch(ex) {
			console.warn('bad parent format', ex);
		}
		var dates = {};
		for(var field in fields){
			if (DATE_TYPES.indexOf(fields[field].base_type) > -1 && (!fields[field].internal_type || fields[field].internal_type.indexOf('date') > -1)){
				dates[field] = fields[field];
			}
		}
		return _mapFieldsArrayByKeys(dates, topLevel);
	}
	function _mapFieldsArrayByKeys(fields, topLevel){
		return Object.keys(fields)
			.filter(function(field){
				return !(fields[field].filterable === false) && fields[field].label;
			})
			.map(function(field){
				var iterativeField = fields[field];
				var obj = {
					base_type: iterativeField.base_type,
					field: topLevel ? topLevel + '.' + iterativeField.name : iterativeField.name,
					field_label: iterativeField.label,
					selected: iterativeField.selected || false
				};
				if ("reference" in iterativeField && iterativeField.type !== "glide_list" && iterativeField.base_type != 'item_option_new')
					obj.reference = iterativeField.reference;
				return obj;
			})
			.sort(function(a, b){
				if (a.field_label.toLowerCase() < b.field_label.toLowerCase())
					return -1;
				if (a.field_label.toLowerCase() > b.field_label.toLowerCase())
					return 1;
				return 0;
			});
	}
	function removeUnwantedColumnsFromDotwalkedMetadata(panelIndex, columns) {
		if (!columns || typeof columns !== 'object') {
			return {};
		}
		
		if (panelIndex > 0 && columns[SYS_TAGS]) {
			delete columns[SYS_TAGS];
		}
		if (panelIndex > 0 && columns[VARIABLES]) {
			delete columns[VARIABLES];
		}
		return columns;
	}
});
;
/*! RESOURCE: /scripts/sn/filter_widget/dot_walk/factory.snDotWalkTableData.js */
angular.module('sn.filter_widget.dot_walk').factory('snDotWalkTableData', function ($http, $q, i18n, snFilterUtilities, snDotWalkTableAPI, snDotWalkUtilities, KEYWORD_FIELD) {
	return {
		getDataByField : getDataByField,
		getTableData: getTableData,
		getFieldsLists: getFieldsLists,
		getVariablesLists: getVariablesLists
	};
	function getDataByField(field, table){
		switch(field.base_type){
			case  "variables" :
				return snDotWalkTableAPI.getCatalogItems(table);
			case "variable" :
				return snDotWalkTableAPI.getVariablesByCatalogID(field.id, table);
case "extended_table":
			default:
				return snDotWalkTableAPI.getMetaData(field.reference);
		}
	}
	function getTableData(table){
		return snDotWalkTableAPI.getTableData(table).then(function(response){
			var fieldsModel = {};
			angular.forEach(response.data.result, function(item){
				fieldsModel[item.name] = {
					filterable: true,
					name: item.name,
					label: item.sys_name,
					base_type: "variable",
					type: "variable",
					non_selectable: true,
					reference: "item_option_new",
					id: item.sys_id
				}
			});
			return fieldsModel;
		});
	}
	function getVariablesLists(comparison, fieldList, table){
		var allPromises = [];
		var lastPromise = $q.when();
		var query = "sys_id=" + comparison.field;
		var catItemId;
		lastPromise = lastPromise.then(function() {
			return snDotWalkTableAPI.getTableData("item_option_new", query).then(function(result) {
				catItemId = result[0].cat_item.value;
			});
		});
		allPromises.push(lastPromise = lastPromise.then(function(){
			return snDotWalkTableAPI.getMetaData(comparison.table).then(function(columns) {
				if(fieldList.length > 0)
					columns = filterTableColumns(columns, fieldList);
				return {
					fields: columns,
					field: 'variables',
					field_label: i18n.getMessage('Variables')
				};
			})
		}));
		allPromises.push(lastPromise = lastPromise.then(function(){
			return snDotWalkTableAPI.getCatalogItems(table).then(function(response){
				var field = Object.keys(response).filter(function(field){ return (response[field].id === catItemId)})[0];
				return {
					fields: response,
					field: field
				}
			});
		}));
		allPromises.push(lastPromise = lastPromise.then(function(){
			return snDotWalkTableAPI.getVariablesByCatalogID(catItemId, comparison.table).then(function(response){
				var field = Object.keys(response).filter(function(field){ return (response[field].name === comparison.field)})[0];
				return {
					fields: response,
					field: field
				}
			});
		}));
		return allPromises;
	}
	function getFieldsLists(comparison, wantKeywords, extendedOperatorOptions, fieldList, includeVariables){
		var tableNames = [comparison.table];
		var fieldLabels = [];
		var fieldsSetsFields = [];
		var lastPromise = $q.when();
		var allPromises = [];
		if (comparison && comparison.reference_fields){
			angular.forEach(comparison.reference_fields, function(item, index, array){
				if (item.reference_table && (array.length - 1 !== index))
					tableNames.push(item.reference_table);
				fieldsSetsFields.push(item.field);
				fieldLabels.push(item.field_label);
			});
		} else if (comparison){
			fieldLabels.push(comparison.field_label);
			fieldsSetsFields.push(comparison.field);
		}
		tableNames.map(function(name, index) {
			var correctTable = (comparison && comparison.reference_fields) ? comparison.reference_fields[index - 1] : null;
			var isExtendedTable = correctTable && correctTable.internal_type === "extended_table";
			if (isExtendedTable) {
				wantKeywords = false;
				includeVariables = false;
			}
			lastPromise = lastPromise.then(function() {
					return snDotWalkTableAPI.getMetaData(name, false, wantKeywords, extendedOperatorOptions,
						includeVariables).then(function(columns) {
							columns = snDotWalkUtilities.removeUnwantedColumnsFromDotwalkedMetadata(index, columns);
							if(fieldList.length > 0)
								columns = filterTableColumns(columns, fieldList);
							return {
								fields: columns,
								field: fieldsSetsFields[index],
								field_label: fieldLabels[index]
							};
					})
				});
				allPromises.push(lastPromise);
		});
		return allPromises;
	}
	function filterTableColumns(columns, filterColumns) {
		var processedColumns = {};
		angular.forEach(filterColumns, function(column) {
			if(columns[column])
				processedColumns[column] = columns[column];
		});
		if(columns[KEYWORD_FIELD])
			processedColumns[KEYWORD_FIELD] = columns[KEYWORD_FIELD];
		return processedColumns;
	}
});
;
/*! RESOURCE: /scripts/sn/filter_widget/dot_walk/factory.snDotWalkTableAPI.js */
angular.module('sn.filter_widget.dot_walk').factory('snDotWalkTableAPI', function ($http, $q, $rootScope, snFilterSubjectCriteriaStore, snFilterSecurityAttributesStore) {
	"use strict";
var META_ENDPOINT = "/api/now/ui/meta/";
var DATA_ENDPOINT = "/api/now/table/";
var FILTER_VARIABLES = "/api/now/ui/filter_variables/";
	return {
		getTableData: getTableData,
		getMetaData : getMetaData,
		getCatalogItems: getCatalogItems,
		getVariablesByCatalogID: getVariablesByCatalogID
	};
	function isValidTableName(tableName) {
return !/[.%]/.test(tableName);
	}
	function getTableData(table, query){
		query = (typeof query !== "undefined") ? "?sysparm_query=" + query : "";
		if(!isValidTableName) {
			return $q.reject("invalid table name");
		}
		return $http.get(DATA_ENDPOINT + table + query, {cache: true}).then(function(response){
			return response.data.result;
		})
	}
	function getMetaData(table, isExtendedTable, wantKeywords, extendedOperatorOptions, includeVariables) {
		if(!isValidTableName(table)) {
			return $q.reject("invalid table name");
		}
        var isSubjectCriteria = snFilterSubjectCriteriaStore.isSubjectCriteria(table);
		var isSecurityAttributes = snFilterSecurityAttributesStore.isSecurityAttributes(table);
		$rootScope.$emit("snfilter:get_meta_data", true);
        var url;
if (isSubjectCriteria === true || isSecurityAttributes === true) {
			if (isSubjectCriteria === true) {
				url = snFilterSubjectCriteriaStore.getAttributeURL(table);
			} else if (isSecurityAttributes === true) {
				url = snFilterSecurityAttributesStore.getAttributeURL(table);
			}
        } else {
            url = META_ENDPOINT + table + "?sysparm_operators=true&sysparm_get_extended_tables=true";
            url += wantKeywords ? "&sysparm_keywords=true" : "";
            url += isExtendedTable ? "&sysparm_is_extended_table=true" : "";
            if (typeof includeVariables === "boolean")
                url += includeVariables ? "" : "&sysparm_includes_variables=false";
            if (extendedOperatorOptions && extendedOperatorOptions.table && extendedOperatorOptions.field) {
                url += ("&sysparm_extended_operators_table=" + extendedOperatorOptions.table);
                url += ("&sysparm_extended_operators_field=" + extendedOperatorOptions.field);
            }
        }
		return $http.get(url, {cache: true}).then(function(response){
			return response.data.result.columns;
		})
	}
	function getCatalogItems(table) {
		var url = FILTER_VARIABLES + "catalog_items";
		if (table)
			url += "?sysparm_base_table=" + table;
		return $http.get(url).then(function(response) {
			return response.data.result;
		});
	}
	function getVariablesByCatalogID (catID, variableTable) {
		return $http.get(FILTER_VARIABLES + "variable_pool?sysparm_cat_item_id=" + (catID !== undefined ? catID : "") + "&sysparm_variable_table=" + variableTable).then(function(response){
			return response.data.result;
		})
	}
});
;
;
