angular.module("sn.filter_widget").directive("snFilterComparison", function(getTemplateUrl) {
	"use strict";
	return {
		restrict: 'E',
		replace: true,
		templateUrl: getTemplateUrl("sn_filter_comparison.xml"),
		controller: function($scope){
			$scope.operatorExpanded = false;
			$scope.operatorExpandedToggle = function(bool) {
				$scope.operatorExpanded = bool;
			}
			$scope.operatorChange = function() {
				$scope.operatorExpandedToggle(false)
				if ($scope.comparison)
					$scope.comparison.operatorSelectChange();
			}
			$scope.operatorKeypress = function(event) {
				if (!event) return;
				var charCode = event.charCode;
				if (charCode === 32)
					$scope.operatorExpandedToggle(true);
			}
			$scope.filterRowKeypress = function(event) {
				if (!event) return;
				var enterKey = 13;
				if ((event.charCode === enterKey || event.key === 'Enter') && event.target.type !== 'textarea') {
					event.preventDefault();
				}
			}
		}
	}
});
