/*! RESOURCE: /scripts/directive.snFilterRelatedListComparison.js */
angular.module("sn.filter_widget").directive("snFilterRelatedListComparison", function(getTemplateUrl, i18n, snCustomEvent) {
	"use strict";
	return {
		restrict: 'E',
		replace: true,
		templateUrl: getTemplateUrl("sn_related_list_comparison.xml"),
		controller: function($scope, $element) {
			var rlcm;
			var container = $scope.popoverConfig.container;
			$scope.popoverConfig = {
				closeBtnClass: "filter-related-list-close-button",
				placement: 'bottom',
				container: angular.isDefined(container) ? container : $element,
				viewport :{
					selector: '.related-list-query-section',
					padding: 10
				},
template: '<div class="popover" role="dialog"><div class="arrow"></div><div class="popover-header popover-header-buttons"><h4>' + i18n.getMessage("Quantity") + '</h4><div class="pull-right"> <button type="button" class="btn btn-icon btn-sm icon-cross filter-related-list-close-button"><span class="sr-only">Close</span></button> </div> </div><div class="popover-content filter-related-list-comparison"></div></div>'
			};
$scope.ref = 'related_comparison';
			$scope.closeEvent = "snfilter:close_related_comparison";
			var relatedComparisonsModel = {
				">=" : {
					operatorLabel : i18n.getMessage("Greater than or Equal to"),
					operatorValue : ">="
				},
				">" : {
					operatorLabel : i18n.getMessage("Greater than"),
					operatorValue : ">"
				},
				"<=" : {
					operatorLabel : i18n.getMessage("Less than or Equal to"),
					operatorValue : "<="
				},
				"<" : {
					operatorLabel : i18n.getMessage("Less than"),
					operatorValue : "<"
				},
				"=" : {
					operatorLabel : i18n.getMessage("Equal to"),
					operatorValue : "="
				},
				"=0" : {
					operatorLabel : i18n.getMessage("None"),
					operatorValue : "=0",
					none : true
				},
				"BETWEEN" : {
					operatorLabel : i18n.getMessage("Between"),
					operatorValue : "BETWEEN",
					between : true
				}
			};
			$scope.relatedComparisonOperators = Object.keys(relatedComparisonsModel).map(function(key, index, array){
				return relatedComparisonsModel[key];
			});
			function RelatedListComparisonModel(operator, value){
				if (operator)
					this.model = angular.extend({}, relatedComparisonsModel[operator]);
				else {
					this.model = this._getDefaultModel();
					value = "1";
				}
				this.initialize(value);
			}
			RelatedListComparisonModel.prototype = {
				initialize : function(value) {
					if (!this.model)
						throw "No Model set in RelatedListComparisonModel";
					this.updateValue(value);
					if (this.model.between)
						this._initBetween();
					else
						this.model.between = false;
				},
				updateValue : function(value){
					this.model.value = value;
					this.model.displayValue = this._getDisplayValue(value);
				},
				updateOperator : function(operator){
					var operatorModel = relatedComparisonsModel[operator];
					this.model.operatorValue = operatorModel.operatorValue;
					this.model.operatorLabel = operatorModel.operatorLabel;
					this.model.none = (typeof operatorModel.none !== "undefined");
					this.model.between = (typeof operatorModel.between !== "undefined");
					if (this.model.between)
						this._initBetween();
					else
						this._sanitizeValue();
					if(this.model.none){
						this.updateValue("0");
						this.model.displayValue = "";
						this.model.operatorLabel = "No";
					}
				},
				getModel : function() {
					return this.model;
				},
				_sanitizeValue : function(){
					if (!this.model || !this.model.value)
						return;
					if (this.model.value.indexOf("@") > -1)
						this.updateValue(this.model.value.split("@")[0]);
				},
				_initBetween : function() {
					if (!typeof this.model.value === "string")
						return
					var splitValue = this.model.value.split("@");
					if (splitValue.length == 1)
						splitValue.push(splitValue[0]);
					this.updateValue(splitValue.join("@"));
					this.model.firstBetweenValue = splitValue[0];
					this.model.secondBetweenValue = splitValue[1];
				},
				_getDefaultModel : function(){
					var model = angular.extend({}, relatedComparisonsModel[">="]);
					return model;
				},
				_getDisplayValue : function(value) {
					value = value + "";
					var andString;
					if (!value)
						return "";
					if (value.indexOf("@") > -1){
						andString = i18n.getMessage(" " + i18n.getMessage("and") + " ");
						return value.split("@").join(andString);
					} else
						return value;
				}
			};
			$scope.relatedListComparisonOperatorChange = relatedListComparisonOperatorChange;
			$scope.relatedListComparisonValueChange = relatedListComparisonValueChange;
			$scope.formatBetween = formatBetween;
			$scope.closePopover = closePopover;
			activate();
			function activate(){
				rlcm = new RelatedListComparisonModel($scope.predicate.comparison.quantity.operator, $scope.predicate.comparison.quantity.value);
				$scope.relatedListComparisonModel = rlcm.getModel();
				updatePredicateComparison();
			}
			function relatedListComparisonOperatorChange(operator){
				if (!operator)
					return;
				rlcm.updateOperator(operator);
				$scope.relatedListComparisonModel = rlcm.getModel();
				$scope.disabledInput = ($scope.relatedListComparisonModel.none === true);
				updatePredicateComparison();
				snCustomEvent.fire('snfilter:conditionChange');
			}
			function relatedListComparisonValueChange (value){
				if (!value)
					return;
				rlcm.updateValue(value);
				$scope.relatedListComparisonModel = rlcm.getModel();
				updatePredicateComparison();
				snCustomEvent.fire('snfilter:conditionChange');
			}
			$scope.$watch('predicate.comparison.quantity.value', function(n, o) {
				if (n !== o && n === undefined)
					updatePredicateComparison();
			});
			$scope.$watch('predicate.comparison.table', function(n, o) {
				if (n !== o && n === undefined)
					$scope.removeTable();
			});
			function updatePredicateComparison(){
				$scope.predicate.comparison.quantity.operator_label = $scope.relatedListComparisonModel.operatorLabel;
				$scope.predicate.comparison.quantity.operator = $scope.relatedListComparisonModel.operatorValue;
				$scope.predicate.comparison.quantity.value = $scope.relatedListComparisonModel.value;
				$scope.predicate.comparison.quantity.display_value = $scope.relatedListComparisonModel.displayValue;
			}
			function closePopover(){
				$scope.$broadcast($scope.closeEvent);
			}
			function formatBetween(){
				if (!$scope.relatedListComparisonModel.firstBetweenValue || !$scope.relatedListComparisonModel.secondBetweenValue)
					return;
				var value = $scope.relatedListComparisonModel.firstBetweenValue + "@" + $scope.relatedListComparisonModel.secondBetweenValue;
				relatedListComparisonValueChange(value);
			}
		},
		link : function(scope, element){
			angular.element(element).on('click', '.filter-related-list-close-button', function(e){
				scope.closePopover();
			})
		}
	}
});
;
/*! RESOURCE: /scripts/directive.snDisabledExplanation.js */
angular.module("sn.filter_widget").directive("snDisabledExplanation", function() {
	"use strict";
	var DISABLED_CLASS = "sn-disabled-explanation";
	function makeHelp(placement, message) {
		var span = document.createElement("span");
		span.style = "display: inline-block;";
		span.setAttribute("title", message);
		span.setAttribute("tabindex", 0);
		span.setAttribute("data-placement", placement);
		span.classList.add(DISABLED_CLASS);
		return span;
	}
	return {
		restrict: "A",
		scope: {
			snDisabledExplanation: "@",
			placement: "@"
		},
		link: function($scope, $element) {
			$scope.$watch(function() {
				var isDisabled = $element.prop("disabled");
				var isWrapped = $element.parent().is("." + DISABLED_CLASS);
				if (isDisabled && !isWrapped) {
					$element.wrap(makeHelp($scope.placement, $scope.snDisabledExplanation));
				}
				if (!isDisabled && isWrapped) {
					$element.unwrap();
				}
			});
		}
	};
});
;
/*! RESOURCE: /scripts/elements/directive.formFilterWidget.js */
angular.module('sn.filter_widget').directive('formFilterWidget', function(snCustomEvent, $http) {
	return {
		scope: {
			ref: '@',
			initialQuery: '@',
			dependentField: '@',
			dependentTable: '@',
			restrictedFields: '@',
			extendedOperators: '@',
			staticDependent: '@',
			allowOrder: '=',
			allowRelatedListQuery: '=',
            		subjectCriteria: '=',
			securityAttributes: '=',
			showConditionCount: '=',
			usageContext: '@'
		},
template: "<div class='form-control-static' ng-if='readOnly' ng-bind='readOnlyText'></div>" +
"<sn-filter-widget ng-if='table' ng-show='!readOnly' table='{{ table }}' filter-config='filterConfig' />",
		replace: false,
		controller: function($scope) {
			var readOnlyFilter = "";
			$scope.$watch('readOnly', function(newValue) {
				if (newValue)
					updateReadOnlyFilter($scope.filterConfig.encodedQuery);
			})
			$scope.$watch('filterConfig.encodedQuery', function(newValue) {
				updateReadOnlyFilter(newValue);
			});
			function updateReadOnlyFilter(filter) {
				if (!$scope.readOnly)
					return;
				if (filter == readOnlyFilter)
					return;
$http.get('/api/now/ui/breadcrumbs?table=' + $scope.table + '&query=' + encodeURIComponent(filter)).then(function(response) {
					if (!response || !response.data || !response.data.result || !response.data.result.breadcrumb)
						setReadOnlyFilterData(filter, "Error while parsing filter");
					var filterPieces = response.data.result.breadcrumb
						.filter(function(item) {
							return !!item.value;
						})
						.map(function(item) {
							return item.label;
						});
					setReadOnlyFilterData(filter, filterPieces.join(" > ") || "(empty)");
				})
			}
			function setReadOnlyFilterData(filter, filterString) {
				readOnlyFilter = filter;
				$scope.readOnlyText = filterString;
			}
		},
		link: function(scope, element) {
			var dotWalk = true;
			if (scope.subjectCriteria) {
				scope.table = "sys_df_data_filtration";
				dotWalk = false;
			} else if (scope.securityAttributes) {
				scope.table = "sys_security_attribute";
				dotWalk = false;
			} else {
				scope.table = scope.staticDependent || setupDependent();
			}
			var fieldList = scope.restrictedFields ? scope.restrictedFields.split(';') : [];
			scope.filterConfig = {
				encodedQuery: scope.initialQuery,
				outputType: "encoded_query",
				sets: true,
				dotWalking: dotWalk,
				saveFilter: false,
				loadFilter: false,
				clearFilter: false,
				closeFilter: false,
				runFilter: false,
				testFilter: scope.showConditionCount,
				relatedListQueryConditions: scope.allowRelatedListQuery,
				sortFilter: scope.allowOrder,
                isSubjectCriteria: scope.subjectCriteria,
				isSecurityAttributes: scope.securityAttributes,
				watchConfig: true,
				mode: 'automatic',
				fieldList: fieldList,
				popoverContainer: 'form[id="' + element.closest('form[id]').attr('id') + '"]'
			};
			scope.$on('snfilter:update_query', function(someScope, queryString) {
				document.getElementById(scope.ref).value = queryString;
				scope.filterConfig.encodedQuery = queryString;
				onChange(scope.ref);
			});
			g_event_handlers.push({
				fieldName: scope.ref,
				handler: function(control, oldValue, newValue) {
					if (newValue == scope.filterConfig.encodedQuery)
						return;
					scope.$broadcast("snfilter:initialize_query", newValue);
					if (!scope.$root.$$phase)
						scope.$apply();
				}
			})
			function setupDependent() {
				if (g_form.hasField(scope.dependentField)) {
					g_event_handlers.push({
						fieldName: scope.dependentField,
						handler: function(control, oldValue, newValue) {
							scope.table = scope.dependentTable = newValue;
							if (!scope.table) {
								g_form.setValue(scope.ref, "");
								return;
							}
							scope.$broadcast('snfilter:update_table', {table: scope.table});
							if (!scope.$root.$$phase)
								scope.$apply();
						}
					})
				}
				return g_form.getValue(scope.dependentField);
			}
			g_form.registerHandler(scope.ref, {
				setReadOnly: function(value) {
					scope.readOnly = value;
					if (!scope.$root.$$phase)
						scope.$apply();
				}
			});
		}
	}
});
;
